impl WorldEnterLoadingState {
    pub fn scene_model(&self) -> WorldEnterSceneModel {
        let blocking_tag_labels = self
            .blocking_tags
            .iter()
            .map(|tag| world_enter_blocking_tag_label(tag).to_string())
            .collect::<Vec<_>>();
        let status_text = match self.status {
            WorldEnterLoadingStatus::Ready => "Ready to enter world".to_string(),
            WorldEnterLoadingStatus::Blocked if blocking_tag_labels.is_empty() => {
                "Blocked".to_string()
            }
            WorldEnterLoadingStatus::Blocked => {
                format!("Blocked: {}", blocking_tag_labels.join(", "))
            }
        };

        WorldEnterSceneModel {
            locale: self.locale.clone(),
            title_text: self
                .display_title
                .clone()
                .unwrap_or_else(|| "Loading world".to_string()),
            status_text,
            blocking_tag_labels,
            can_enter_world: self.status == WorldEnterLoadingStatus::Ready,
        }
    }
}

impl WorldEnterSceneModel {
    pub fn view_model(&self) -> WorldEnterViewModel {
        let blocked_hint_text = if self.can_enter_world {
            None
        } else if self.blocking_tag_labels.is_empty() {
            Some("Resolve loading blockers before entering".to_string())
        } else {
            Some(format!("Resolve: {}", self.blocking_tag_labels.join(", ")))
        };

        WorldEnterViewModel {
            locale: self.locale.clone(),
            title_text: self.title_text.clone(),
            status_text: self.status_text.clone(),
            blocking_tag_labels: self.blocking_tag_labels.clone(),
            primary_action_label: if self.can_enter_world {
                "Enter world".to_string()
            } else {
                "Blocked".to_string()
            },
            primary_action_enabled: self.can_enter_world,
            blocked_hint_text,
        }
    }
}

impl WorldEnterViewModel {
    pub fn component_model(&self) -> WorldEnterComponentModel {
        WorldEnterComponentModel {
            locale: self.locale.clone(),
            title_text: self.title_text.clone(),
            status_text: self.status_text.clone(),
            show_primary_action: self.primary_action_enabled,
            primary_action_label: self.primary_action_label.clone(),
            show_blocked_hint: self.blocked_hint_text.is_some(),
            blocked_hint_text: self.blocked_hint_text.clone(),
            show_blocking_tags: !self.blocking_tag_labels.is_empty(),
            blocking_tag_labels: self.blocking_tag_labels.clone(),
        }
    }
}

impl WorldEnterComponentModel {
    pub fn surface_contract(&self) -> WorldEnterSurfaceContract {
        WorldEnterSurfaceContract {
            locale: self.locale.clone(),
            title: WorldEnterTextSurfaceContract {
                visible: true,
                text: Some(self.title_text.clone()),
            },
            status: WorldEnterTextSurfaceContract {
                visible: true,
                text: Some(self.status_text.clone()),
            },
            primary_action: WorldEnterActionSurfaceContract {
                visible: self.show_primary_action,
                enabled: self.show_primary_action,
                label: self.primary_action_label.clone(),
            },
            blocked_hint: WorldEnterTextSurfaceContract {
                visible: self.show_blocked_hint,
                text: self.blocked_hint_text.clone(),
            },
            blocking_tags: WorldEnterTagsSurfaceContract {
                visible: self.show_blocking_tags,
                labels: self.blocking_tag_labels.clone(),
            },
        }
    }
}

impl WorldEnterSurfaceContract {
    pub fn layout_contract(&self) -> WorldEnterLayoutContract {
        let mut section_order = vec!["title".to_string(), "status".to_string()];
        if self.primary_action.visible {
            section_order.push("primaryAction".to_string());
        }
        if self.blocked_hint.visible {
            section_order.push("blockedHint".to_string());
        }
        if self.blocking_tags.visible {
            section_order.push("blockingTags".to_string());
        }

        WorldEnterLayoutContract {
            locale: self.locale.clone(),
            section_order,
            title: WorldEnterLayoutSlot {
                slot: "header.title".to_string(),
                visible: self.title.visible,
            },
            status: WorldEnterLayoutSlot {
                slot: "header.status".to_string(),
                visible: self.status.visible,
            },
            primary_action: WorldEnterLayoutSlot {
                slot: "footer.primaryAction".to_string(),
                visible: self.primary_action.visible,
            },
            blocked_hint: WorldEnterLayoutSlot {
                slot: "body.blockedHint".to_string(),
                visible: self.blocked_hint.visible,
            },
            blocking_tags: WorldEnterLayoutSlot {
                slot: "body.blockingTags".to_string(),
                visible: self.blocking_tags.visible,
            },
        }
    }
}

impl WorldEnterLayoutContract {
    pub fn page_contract(&self) -> WorldEnterPageContract {
        let mut header_regions = Vec::new();
        if self.title.visible {
            header_regions.push(WorldEnterPageRegion {
                name: "title".to_string(),
                slot: self.title.slot.clone(),
            });
        }
        if self.status.visible {
            header_regions.push(WorldEnterPageRegion {
                name: "status".to_string(),
                slot: self.status.slot.clone(),
            });
        }

        let mut body_regions = Vec::new();
        if self.blocked_hint.visible {
            body_regions.push(WorldEnterPageRegion {
                name: "blockedHint".to_string(),
                slot: self.blocked_hint.slot.clone(),
            });
        }
        if self.blocking_tags.visible {
            body_regions.push(WorldEnterPageRegion {
                name: "blockingTags".to_string(),
                slot: self.blocking_tags.slot.clone(),
            });
        }

        let mut footer_regions = Vec::new();
        if self.primary_action.visible {
            footer_regions.push(WorldEnterPageRegion {
                name: "primaryAction".to_string(),
                slot: self.primary_action.slot.clone(),
            });
        }

        WorldEnterPageContract {
            locale: self.locale.clone(),
            header_regions,
            body_regions,
            footer_regions,
        }
    }
}

impl WorldEnterPageContract {
    pub fn screen_contract(
        &self,
        loading: &WorldEnterLoadingState,
        view: &WorldEnterViewModel,
    ) -> WorldEnterScreenContract {
        let primary_action_outlet = self
            .footer_regions
            .iter()
            .find(|region| region.name == "primaryAction")
            .map(|region| region.slot.clone());
        let primary_action_enabled = view.primary_action_enabled && primary_action_outlet.is_some();

        WorldEnterScreenContract {
            locale: self.locale.clone(),
            screen_id: "world.enter".to_string(),
            page_id: format!("world.enter.{}", loading.status.as_str()),
            status: loading.status,
            primary_action: WorldEnterScreenAction {
                outlet: primary_action_outlet,
                action_id: primary_action_enabled.then(|| "enter-world".to_string()),
                label: primary_action_enabled.then(|| view.primary_action_label.clone()),
                enabled: primary_action_enabled,
                target: if primary_action_enabled {
                    "world".to_string()
                } else {
                    "stay".to_string()
                },
            },
        }
    }
}

impl WorldEnterScreenContract {
    pub fn transition_contract(&self, state: &WorldEnterInitState) -> WorldEnterTransitionContract {
        let allowed = self.primary_action.enabled
            && self.primary_action.target == "world"
            && state.is_ready();

        WorldEnterTransitionContract {
            locale: self.locale.clone(),
            source_screen_id: self.screen_id.clone(),
            action_id: self.primary_action.action_id.clone(),
            target_screen_id: if allowed {
                self.primary_action.target.clone()
            } else {
                self.screen_id.clone()
            },
            allowed,
            handoff: allowed.then(|| WorldEnterWorldHandoff {
                display_title: state.player.display_title.clone(),
                player_id: state.player.player_id,
                player_team_id: state.player.player_team_id,
                map_width: state.world.map_width,
                map_height: state.world.map_height,
                core_tile_index: state.world.core_tile_index,
                total_plans: state.overlay.total_plans,
                tail_sha256: state.transport.tail_sha256.clone(),
            }),
        }
    }
}

impl WorldEnterTransitionContract {
    pub fn world_ready_contract(
        &self,
        state: &WorldEnterInitState,
        bootstrap: &LoadedWorldBootstrap,
    ) -> WorldEnterWorldReadyContract {
        WorldEnterWorldReadyContract {
            locale: self.locale.clone(),
            screen_id: if self.allowed {
                self.target_screen_id.clone()
            } else {
                self.source_screen_id.clone()
            },
            ready: self.allowed,
            wave: bootstrap.wave,
            wavetime_bits: bootstrap.wavetime_bits,
            tick_bits: bootstrap.tick_bits,
            rand0: bootstrap.rand0,
            rand1: bootstrap.rand1,
            static_fog_team_count: bootstrap.static_fog_team_count,
            hud: WorldEnterWorldReadyHudContract {
                visible: self.allowed,
                title_text: self
                    .allowed
                    .then(|| bootstrap.display_title.clone())
                    .flatten(),
                wave_text: self.allowed.then(|| format!("Wave {}", bootstrap.wave)),
                fog_enabled: self
                    .allowed
                    .then(|| state.context.rules.get("fog").and_then(JsonValue::as_bool))
                    .flatten(),
            },
            camera: WorldEnterWorldReadyCameraContract {
                anchor_tile_index: bootstrap.core_tile_index,
                player_x_bits: bootstrap.player_x_bits,
                player_y_bits: bootstrap.player_y_bits,
                mouse_x_bits: bootstrap.mouse_x_bits,
                mouse_y_bits: bootstrap.mouse_y_bits,
            },
        }
    }
}

