impl WorldEnterLoopContract {
    pub fn render_contract(&self, play: &WorldEnterPlayContract) -> WorldEnterRenderContract {
        let hud_status_text = if play.hud.visible {
            match (&play.hud.wave_text, play.hud.fog_enabled) {
                (Some(wave_text), Some(true)) => Some(format!("{wave_text} · Fog enabled")),
                (Some(wave_text), Some(false)) => Some(format!("{wave_text} · Fog disabled")),
                (Some(wave_text), None) => Some(wave_text.clone()),
                (None, Some(true)) => Some("Fog enabled".to_string()),
                (None, Some(false)) => Some("Fog disabled".to_string()),
                (None, None) => None,
            }
        } else {
            None
        };
        let overlay_visible = play.overlay.visible && self.running;
        let overlay_summary_text = overlay_visible.then(|| {
            format!(
                "Plans {} · Markers {} · Fog teams {}",
                self.overlay.total_plans,
                self.overlay.marker_count,
                self.overlay.static_fog_team_count
            )
        });

        WorldEnterRenderContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            drawable: self.running,
            tick_bits: self.tick_bits,
            rand0: self.rand0,
            rand1: self.rand1,
            camera: WorldEnterRenderCameraContract {
                strategy: self.focus.strategy.clone(),
                team_id: self.focus.team_id,
                anchor_tile_index: self.focus.anchor_tile_index,
            },
            hud: WorldEnterRenderHudContract {
                visible: play.hud.visible,
                title_text: play.hud.title_text.clone(),
                wave_text: play.hud.wave_text.clone(),
                status_text: hud_status_text,
            },
            overlay: WorldEnterRenderOverlayContract {
                visible: overlay_visible,
                refresh_mode: self.overlay.refresh_mode.clone(),
                dirty: self.overlay.dirty,
                marker_ids: self.overlay.marker_ids.clone(),
                marker_count: self.overlay.marker_count,
                total_plans: self.overlay.total_plans,
                static_fog_team_count: self.overlay.static_fog_team_count,
                summary_text: overlay_summary_text,
            },
        }
    }
}

