impl WorldEnterScenePresentContract {
    pub fn world_shell_contract(
        &self,
        transition: &WorldEnterTransitionContract,
    ) -> WorldEnterWorldShellContract {
        let mounted =
            self.presentable && transition.allowed && transition.target_screen_id == self.screen_id;
        WorldEnterWorldShellContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            active: mounted,
            tick_bits: self.tick_bits,
            rand0: self.rand0,
            rand1: self.rand1,
            mount: WorldEnterWorldShellMountContract {
                root_slot: self.scene.root_slot.clone(),
                child_order: vec![
                    self.scene.menu_group_slot.clone(),
                    self.scene.hud_group_slot.clone(),
                    "core.scene.loadfrag".to_string(),
                    "core.scene.fadeIn".to_string(),
                ],
                source_screen_id: transition.source_screen_id.clone(),
                action_id: transition.action_id.clone(),
                target_screen_id: transition.target_screen_id.clone(),
                mounted,
            },
            visibility: WorldEnterWorldShellVisibilityContract {
                hud_group_slot: self.scene.hud_group_slot.clone(),
                hud_group_visible: self.scene.hud_attached && mounted,
                menu_group_slot: self.scene.menu_group_slot.clone(),
                menu_group_visible: self.scene.menu_attached && !mounted,
                scene_hud_slot: self.scene.hud_slot.clone(),
                scene_hud_visible: self.scene.hud_attached && mounted,
            },
        }
    }
}

