impl WorldEnterSessionActivationContract {
    pub fn connection_ready_contract(&self) -> WorldEnterConnectionReadyContract {
        let net = WorldEnterConnectionReadyNetContract {
            client_loaded: true,
            connect_confirm_posted: true,
            player_connection_confirmed: true,
        };
        let ui = WorldEnterConnectionReadyUiContract {
            join_hidden: true,
            loadfrag_hidden: true,
        };
        let ready = self.state.complete
            && net.client_loaded
            && net.connect_confirm_posted
            && net.player_connection_confirmed
            && ui.loadfrag_hidden;
        WorldEnterConnectionReadyContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            ready,
            completion_rule: "net.setClientLoaded(true)+connectConfirm+ui.loadfrag.hide"
                .to_string(),
            source_screen_id: self.source_screen_id.clone(),
            action_id: self.action_id.clone(),
            target_screen_id: self.target_screen_id.clone(),
            net,
            ui,
            session_complete: self.state.complete,
        }
    }
}

impl WorldEnterConnectionReadyContract {
    pub fn ready_proof_contract(
        &self,
        entry_envelope_proof: &WorldEnterPlayableSessionEntryEnvelopeProofContract,
    ) -> WorldEnterReadyProofContract {
        let wrapper_playable = entry_envelope_proof.wrapper_playable;
        let connection_ready_matches_wrapper = self.ready == wrapper_playable;
        let ready = self.ready && entry_envelope_proof.ready;
        let live = self.ready && entry_envelope_proof.live;
        let playable = self.ready && entry_envelope_proof.playable && wrapper_playable;

        WorldEnterReadyProofContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            ready,
            live,
            playable,
            completion_rule: "connectionReady+entryEnvelopeProof".to_string(),
            source_screen_id: self.source_screen_id.clone(),
            action_id: self.action_id.clone(),
            target_screen_id: self.target_screen_id.clone(),
            connection_ready: self.ready,
            connection_ready_completion_rule: self.completion_rule.clone(),
            net: self.net.clone(),
            ui: self.ui.clone(),
            ready_to_enter_world: self.ready && entry_envelope_proof.ready_to_enter_world,
            updates_ping: entry_envelope_proof.updates_ping,
            session_complete: self.session_complete && entry_envelope_proof.session_complete,
            wrapper_playable,
            wrapper_completion_rule: entry_envelope_proof.wrapper_completion_rule.clone(),
            wrapper_playable_matches_entry: entry_envelope_proof.wrapper_playable_matches_entry,
            connection_ready_matches_wrapper,
            entry_envelope_proof: entry_envelope_proof.clone(),
        }
    }

    pub fn connection_confirmed_contract(&self) -> WorldEnterConnectionConfirmedContract {
        let player = WorldEnterConnectionConfirmedPlayerContract { added: self.ready };
        let events = WorldEnterConnectionConfirmedEventContract {
            player_connection_confirmed: self.net.player_connection_confirmed,
        };
        let net = WorldEnterConnectionConfirmedNetContract {
            client_loaded: self.net.client_loaded,
            connect_confirm_posted: self.net.connect_confirm_posted,
            has_connected: self.ready && player.added && events.player_connection_confirmed,
        };
        let ui = WorldEnterConnectionConfirmedUiContract {
            join_hidden: self.ui.join_hidden,
            loadfrag_hidden: self.ui.loadfrag_hidden,
        };
        let confirmed = self.ready
            && self.session_complete
            && net.client_loaded
            && net.connect_confirm_posted
            && net.has_connected
            && ui.join_hidden
            && ui.loadfrag_hidden
            && player.added
            && events.player_connection_confirmed;

        WorldEnterConnectionConfirmedContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            confirmed,
            completion_rule:
                "net.setClientLoaded(true)+connectConfirm+ui.loadfrag.hide+player.add+PlayerConnectionConfirmed+player.con.hasConnected"
                    .to_string(),
            source_screen_id: self.source_screen_id.clone(),
            action_id: self.action_id.clone(),
            target_screen_id: self.target_screen_id.clone(),
            connection_ready: self.ready,
            net,
            ui,
            player,
            events,
            session_complete: self.session_complete,
        }
    }
}

impl WorldEnterReadyProofContract {
    pub fn room_entry_proof_contract(
        &self,
        connection_confirmed: &WorldEnterConnectionConfirmedContract,
        entry_lifecycle_summary: &WorldEnterPlayableSessionEntryLifecycleSummaryContract,
    ) -> WorldEnterRoomEntryProofContract {
        let connection_confirmed_matches_lifecycle = connection_confirmed.confirmed
            == entry_lifecycle_summary.connection_confirmed
            && connection_confirmed.net.has_connected == entry_lifecycle_summary.has_connected
            && connection_confirmed.player.added == entry_lifecycle_summary.player_added;

        WorldEnterRoomEntryProofContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            ready: self.ready && entry_lifecycle_summary.ready && connection_confirmed.confirmed,
            live: self.live && entry_lifecycle_summary.live && connection_confirmed.confirmed,
            playable: self.playable
                && entry_lifecycle_summary.playable
                && connection_confirmed.confirmed,
            completion_rule: "readyProof+connectionConfirmed+entryLifecycleSummary".to_string(),
            source_screen_id: self.source_screen_id.clone(),
            action_id: self.action_id.clone(),
            target_screen_id: self.target_screen_id.clone(),
            ready_proof: self.ready,
            ready_proof_completion_rule: self.completion_rule.clone(),
            connection_confirmed: connection_confirmed.confirmed,
            connection_confirmed_completion_rule: connection_confirmed.completion_rule.clone(),
            has_connected: connection_confirmed.net.has_connected
                && entry_lifecycle_summary.has_connected,
            player_added: connection_confirmed.player.added && entry_lifecycle_summary.player_added,
            player_joined: entry_lifecycle_summary.player_joined,
            player_join_event: entry_lifecycle_summary.player_join_event,
            connection_age_gate_ms: entry_lifecycle_summary.connection_age_gate_ms,
            connection_age_elapsed: entry_lifecycle_summary.connection_age_elapsed,
            ready_to_enter_world: self.ready_to_enter_world
                && entry_lifecycle_summary.ready_to_enter_world,
            updates_ping: self.updates_ping && entry_lifecycle_summary.updates_ping,
            session_complete: self.session_complete
                && connection_confirmed.session_complete
                && entry_lifecycle_summary.session_complete,
            wrapper_playable: self.wrapper_playable,
            wrapper_completion_rule: self.wrapper_completion_rule.clone(),
            connection_ready_matches_wrapper: self.connection_ready_matches_wrapper,
            connection_confirmed_matches_lifecycle,
            ready_proof_contract: self.clone(),
        }
    }
}

impl WorldEnterRoomEntryProofContract {
    pub fn world_loop_proof_contract(
        &self,
        multiplayer_session: &WorldEnterMultiplayerSessionContract,
        entry_proof_summary: &WorldEnterPlayableSessionEntryProofSummaryContract,
    ) -> WorldEnterWorldLoopProofContract {
        let interaction_ready =
            multiplayer_session.interaction_ready && entry_proof_summary.interaction_ready;
        let sync_loop = multiplayer_session.multiplayer_runtime && entry_proof_summary.sync_loop;
        let last_received_snapshot = multiplayer_session.stability.last_received_snapshot;
        let last_received_snapshot_matches_entry =
            last_received_snapshot == entry_proof_summary.last_received_snapshot;
        let updates_ping = self.updates_ping
            && multiplayer_session.stability.updates_ping
            && entry_proof_summary.updates_ping;
        let packet_hex_matches_runtime = entry_proof_summary.packet_hex_matches_runtime;
        let ping_source_matches_runtime = entry_proof_summary.ping_source_matches_runtime;

        WorldEnterWorldLoopProofContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            ready: self.ready && multiplayer_session.live && entry_proof_summary.ready,
            live: self.live && multiplayer_session.live && entry_proof_summary.live,
            playable: self.playable
                && multiplayer_session.live
                && entry_proof_summary.playable
                && interaction_ready
                && sync_loop
                && last_received_snapshot_matches_entry
                && updates_ping
                && packet_hex_matches_runtime
                && ping_source_matches_runtime,
            completion_rule: "roomEntryProof+multiplayerSession+entryProofSummary".to_string(),
            source_screen_id: self.source_screen_id.clone(),
            action_id: self.action_id.clone(),
            target_screen_id: self.target_screen_id.clone(),
            room_entry_proof: self.ready,
            room_entry_proof_completion_rule: self.completion_rule.clone(),
            multiplayer_session: multiplayer_session.live,
            multiplayer_session_completion_rule: multiplayer_session.completion_rule.clone(),
            entry_proof_summary: entry_proof_summary.ready,
            entry_proof_summary_completion_rule: entry_proof_summary.completion_rule.clone(),
            interaction_ready,
            sync_loop,
            last_received_snapshot,
            updates_ping,
            packet_hex_matches_runtime,
            ping_source_matches_runtime,
            ready_to_enter_world: self.ready_to_enter_world
                && entry_proof_summary.ready_to_enter_world,
            session_complete: self.session_complete
                && multiplayer_session.session_complete
                && entry_proof_summary.session_complete,
            room_entry_proof_contract: self.clone(),
        }
    }
}

