    pub fn stable_ready_proof_contract(
        &self,
        connection_ready: &WorldEnterConnectionReadyContract,
    ) -> WorldEnterStableReadyProofContract {
        let connection_ready_matches_wrapper = connection_ready.ready == self.wrapper_playable;
        let stable_envelope_matches_ready = self.ready == connection_ready.ready
            && self.live == connection_ready.ready
            && self.playable == (connection_ready.ready && self.wrapper_playable)
            && self.wrapper_playable_matches_entry
            && self.stable_stage_matches_envelope;

        WorldEnterStableReadyProofContract {
            locale: self.locale.clone(),
            screen_id: self.screen_id.clone(),
            ready: self.ready && connection_ready.ready,
            live: self.live && connection_ready.ready,
            playable: self.playable && connection_ready.ready && stable_envelope_matches_ready,
            completion_rule: "stableEnvelopeProof+connectionReady".to_string(),
            source_screen_id: self.source_screen_id.clone(),
            action_id: self.action_id.clone(),
            target_screen_id: self.target_screen_id.clone(),
            stable_envelope_proof: self.ready,
            stable_envelope_proof_completion_rule: self.completion_rule.clone(),
            connection_ready: connection_ready.ready,
            connection_ready_completion_rule: connection_ready.completion_rule.clone(),
            net: connection_ready.net.clone(),
            ui: connection_ready.ui.clone(),
            ready_to_enter_world: self.ready_to_enter_world && connection_ready.ready,
            updates_ping: self.updates_ping,
            session_complete: self.session_complete && connection_ready.session_complete,
            connection_ready_matches_wrapper,
            stable_envelope_matches_ready,
            stable_envelope_proof_contract: self.clone(),
        }
    }
