pub fn parse_building_base_snapshot_bytes(
    bytes: &[u8],
) -> Result<(BuildingBaseSnapshot, usize), String> {
    let mut reader = Reader::new(bytes);
    let snapshot = parse_building_base_snapshot(&mut reader)?;
    Ok((snapshot, reader.position()))
}

pub fn parse_building_sync_bytes(
    content_header: &[ContentHeaderEntry],
    block_name: Option<&str>,
    revision: u8,
    bytes: &[u8],
) -> Result<(BuildingSnapshot, usize), String> {
    if block_name.is_none() {
        return Err("building sync block name is unknown".into());
    }

    let mut best_match: Option<(BuildingSnapshot, usize)> = None;
    for consumed in 0..=bytes.len() {
        let mut chunk = Vec::with_capacity(consumed + 1);
        chunk.push(revision);
        chunk.extend_from_slice(&bytes[..consumed]);
        if let Ok(snapshot) = parse_building_snapshot(content_header, block_name, &chunk) {
            if !matches!(snapshot.parsed_tail, ParsedBuildingTail::Unknown) {
                best_match = Some((snapshot, consumed));
            }
        }
    }

    if let Some(match_) = best_match {
        return Ok(match_);
    }

    Err(format!(
        "unable to determine building sync boundary for block {:?} revision {}",
        block_name, revision
    ))
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct BuildPayloadSnapshot {
    pub block_id: i16,
    pub build_revision: u8,
    pub building_sync: BuildingSnapshot,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct UnitPayloadSnapshot {
    pub class_id: u8,
    pub revision: i16,
    pub body_len: usize,
    pub body_sha256: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PayloadSnapshot {
    Null,
    Build(BuildPayloadSnapshot),
    Unit(UnitPayloadSnapshot),
}

pub fn parse_payload_snapshot_bytes(
    content_header: &[ContentHeaderEntry],
    bytes: &[u8],
) -> Result<(PayloadSnapshot, usize), String> {
    parse_payload_snapshot_bytes_with_depth(content_header, bytes, 0)
}

fn parse_payload_snapshot_bytes_with_depth(
    content_header: &[ContentHeaderEntry],
    bytes: &[u8],
    depth: usize,
) -> Result<(PayloadSnapshot, usize), String> {
    let mut reader = Reader::new(bytes);
    let (payload_header, prefix_len) =
        read_payload_header_prefix(bytes).map_err(|error| error.to_string())?;
    reader.skip_bytes(prefix_len)?;
    match payload_header {
        TypedPayload::Null => Ok((PayloadSnapshot::Null, reader.position())),
        TypedPayload::Build(header) => {
            let block_id = header.block_id_i16();
            let build_revision = header.build_revision;
            let block_name = if block_id >= 0 {
                resolve_content_name(content_header, BLOCK_CONTENT_TYPE, block_id as u16)
            } else {
                None
            };
            let remaining = reader.remaining_bytes();
            let (building_sync, consumed) =
                parse_building_sync_bytes(content_header, block_name, build_revision, &remaining)
                    .map_err(|error| {
                    error.replace("building sync boundary", "build payload boundary")
                })?;
            reader.skip_bytes(consumed)?;
            Ok((
                PayloadSnapshot::Build(BuildPayloadSnapshot {
                    block_id,
                    build_revision,
                    building_sync,
                }),
                reader.position(),
            ))
        }
        TypedPayload::Unit(header) => {
            let class_id = header.class_id;
            let unit_payload = parse_unit_payload_snapshot_bytes(
                content_header,
                class_id,
                &reader.remaining_bytes(),
                depth,
            )?;
            reader.skip_bytes(unit_payload.body_len)?;
            Ok((PayloadSnapshot::Unit(unit_payload), reader.position()))
        }
    }
}

pub fn parse_entity_player_sync_bytes(
    bytes: &[u8],
) -> Result<(EntityPlayerSyncSnapshot, usize), String> {
    let mut reader = Reader::new(bytes);
    let snapshot = EntityPlayerSyncSnapshot {
        admin: reader.read_bool()?,
        boosting: reader.read_bool()?,
        color_rgba: reader.read_u32()?,
        mouse_x_bits: reader.read_u32()?,
        mouse_y_bits: reader.read_u32()?,
        name: reader.read_nullable_typeio_string()?,
        selected_block_id: reader.read_u16()?,
        selected_rotation: reader.read_u32()?,
        shooting: reader.read_bool()?,
        team_id: reader.read_u8()?,
        typing: reader.read_bool()?,
        unit_kind: reader.read_u8()?,
        unit_value: reader.read_u32()?,
        x_bits: reader.read_u32()?,
        y_bits: reader.read_u32()?,
    };
    if snapshot.unit_kind > 2 {
        return Err(format!(
            "unsupported entity player sync unit kind: {}",
            snapshot.unit_kind
        ));
    }
    if snapshot.unit_kind == 0 && snapshot.unit_value != 0 {
        return Err(format!(
            "dead entity player sync had non-zero unit value: {}",
            snapshot.unit_value
        ));
    }
    if !snapshot.x().is_finite() || !snapshot.y().is_finite() {
        return Err("entity player sync contained non-finite position".to_string());
    }
    Ok((snapshot, reader.position()))
}

pub fn parse_entity_alpha_sync_bytes(
    bytes: &[u8],
) -> Result<(EntityAlphaSyncSnapshot, usize), String> {
    let mut reader = Reader::new(bytes);
    let abilities_len = reader.read_u8()?;
    reader.skip_bytes(usize::from(abilities_len).saturating_mul(4))?;
    let ammo_bits = reader.read_u32()?;
    let (controller_type, controller_value) = skip_entity_unit_controller(&mut reader)?;
    let elevation_bits = reader.read_u32()?;
    let flag_bits = reader.read_u64()?;
    let health_bits = reader.read_u32()?;
    let is_shooting = reader.read_bool()?;
    let mine_tile_pos = reader.read_i32()?;
    let mount_count = reader.read_u8()?;
    reader.skip_bytes(usize::from(mount_count).saturating_mul(9))?;
    let plan_count = reader.read_i32()?;
    if plan_count < 0 {
        return Err(format!(
            "unsupported alpha sync negative plan count: {plan_count}"
        ));
    }
    for _ in 0..plan_count {
        skip_entity_build_plan(&mut reader)?;
    }
    let rotation_bits = reader.read_u32()?;
    let shield_bits = reader.read_u32()?;
    let spawned_by_core = reader.read_bool()?;
    let stack_item_id = reader.read_i16()?;
    let stack_amount = reader.read_i32()?;
    let status_count = reader.read_i32()?;
    consume_entity_status_entries(&mut reader, status_count, None, "alpha sync")?;
    let snapshot = EntityAlphaSyncSnapshot {
        abilities_len,
        ammo_bits,
        controller_type,
        controller_value,
        elevation_bits,
        flag_bits,
        health_bits,
        is_shooting,
        mine_tile_pos,
        mount_count,
        plan_count,
        rotation_bits,
        shield_bits,
        spawned_by_core,
        stack_item_id,
        stack_amount,
        status_count,
        team_id: reader.read_u8()?,
        unit_type_id: reader.read_i16()?,
        update_building: reader.read_bool()?,
        vel_x_bits: reader.read_u32()?,
        vel_y_bits: reader.read_u32()?,
        x_bits: reader.read_u32()?,
        y_bits: reader.read_u32()?,
    };
    if !snapshot.x().is_finite() || !snapshot.y().is_finite() {
        return Err("entity alpha sync contained non-finite position".to_string());
    }
    Ok((snapshot, reader.position()))
}

