fn parse_unit_payload_snapshot_bytes(
    content_header: &[ContentHeaderEntry],
    class_id: u8,
    bytes: &[u8],
    depth: usize,
) -> Result<UnitPayloadSnapshot, String> {
    if depth >= MAX_UNIT_PAYLOAD_DEPTH {
        return Err(format!(
            "unit payload recursion depth limit exceeded: depth={depth}"
        ));
    }

    let mut successes = Vec::new();
    let mut errors = Vec::new();
    for shape in candidate_unit_payload_shapes(class_id) {
        let mut reader = Reader::new(bytes);
        let revision = match reader.read_i16() {
            Ok(revision) => revision,
            Err(error) => {
                errors.push(error);
                break;
            }
        };
        let result = match shape {
            UnitPayloadShape::AlphaLegacy => {
                consume_alpha_legacy_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::StandardLegacy => {
                consume_standard_legacy_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::MonoLegacy => {
                consume_mono_legacy_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::PolyLegacy => {
                consume_poly_legacy_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::SpiroctLegacy => {
                consume_spiroct_legacy_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::StandardCurrent => {
                consume_standard_current_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::TankLikeCurrent => {
                consume_tank_like_current_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::MechLegacy => {
                consume_mech_legacy_unit_payload_body(&mut reader, content_header, revision)
            }
            UnitPayloadShape::PayloadMegaLike => consume_payload_legacy_like_unit_payload_body(
                &mut reader,
                content_header,
                revision,
                depth,
                PayloadLegacyLikeShape::Mega,
            ),
            UnitPayloadShape::PayloadOctLike => consume_payload_legacy_like_unit_payload_body(
                &mut reader,
                content_header,
                revision,
                depth,
                PayloadLegacyLikeShape::Oct,
            ),
            UnitPayloadShape::PayloadQuadLike => consume_payload_legacy_like_unit_payload_body(
                &mut reader,
                content_header,
                revision,
                depth,
                PayloadLegacyLikeShape::Quad,
            ),
            UnitPayloadShape::BuildingTetherPayload => consume_building_tether_payload_unit_body(
                &mut reader,
                content_header,
                revision,
                depth,
            ),
            UnitPayloadShape::TimedKill => {
                consume_timed_kill_unit_payload_body(&mut reader, content_header, revision)
            }
        };

        match result {
            Ok(()) => successes.push((revision, reader.position())),
            Err(error) => errors.push(error),
        }
    }

    let Some((revision, body_len)) = successes.first().copied() else {
        return Err(format!(
            "unsupported unit payload parser body: class_id={class_id}:{}",
            errors.join(" | ")
        ));
    };

    let distinct_lengths = successes
        .iter()
        .map(|(_, consumed)| *consumed)
        .collect::<BTreeSet<_>>();
    if distinct_lengths.len() > 1 {
        return Err(format!(
            "ambiguous unit payload boundary: class_id={class_id}:lengths={:?}",
            distinct_lengths
        ));
    }

    Ok(UnitPayloadSnapshot {
        class_id,
        revision,
        body_len,
        body_sha256: sha256_hex(&bytes[..body_len]),
    })
}

fn consume_entity_payload_entries(
    reader: &mut Reader<'_>,
    payload_count: i32,
    content_header: Option<&[ContentHeaderEntry]>,
    outer_kind: &str,
) -> Result<(), String> {
    if payload_count == 0 {
        return Ok(());
    }

    let Some(content_header) = content_header else {
        let first_payload = probe_payload_entry(reader)
            .map(|probe| format_payload_entry_probe(&probe))
            .unwrap_or_else(|error| format!("unavailable:{error}"));
        return Err(format!(
            "unsupported {outer_kind} nonzero payload count: {payload_count}:first_payload:{first_payload}"
        ));
    };

    let payload_count = usize::try_from(payload_count).unwrap_or_default();
    for payload_index in 0..payload_count {
        let remaining = reader.remaining_bytes();
        let (_, consumed) =
            parse_payload_snapshot_bytes(content_header, &remaining).map_err(|error| {
                format!("unsupported {outer_kind} payload[{payload_index}]:{error}")
            })?;
        reader.skip_bytes(consumed)?;
    }

    Ok(())
}

pub fn parse_entity_payload_sync_bytes(
    bytes: &[u8],
) -> Result<(EntityPayloadSyncSnapshot, usize), String> {
    parse_entity_payload_sync_bytes_with_content_header_option(None, bytes)
}

pub fn parse_entity_payload_sync_bytes_with_content_header(
    content_header: &[ContentHeaderEntry],
    bytes: &[u8],
) -> Result<(EntityPayloadSyncSnapshot, usize), String> {
    parse_entity_payload_sync_bytes_with_content_header_option(Some(content_header), bytes)
}

fn parse_entity_payload_sync_bytes_with_content_header_option(
    content_header: Option<&[ContentHeaderEntry]>,
    bytes: &[u8],
) -> Result<(EntityPayloadSyncSnapshot, usize), String> {
    let mut reader = Reader::new(bytes);
    let abilities_len = reader.read_u8()?;
    reader.skip_bytes(usize::from(abilities_len).saturating_mul(4))?;
    let ammo_bits = reader.read_u32()?;
    let (controller_type, controller_value) = skip_entity_unit_controller(&mut reader)?;
    let elevation_bits = reader.read_u32()?;
    let flag_bits = reader.read_u64()?;
    let health_bits = reader.read_u32()?;
    let is_shooting = reader.read_bool()?;
    let mine_tile_pos = reader.read_i32()?;
    let mount_count = reader.read_u8()?;
    reader.skip_bytes(usize::from(mount_count).saturating_mul(9))?;
    let payload_count = reader.read_i32()?;
    if payload_count < 0 {
        return Err(format!(
            "unsupported payload sync negative payload count: {payload_count}"
        ));
    }
    consume_entity_payload_entries(&mut reader, payload_count, content_header, "payload sync")?;
    let plan_count = reader.read_i32()?;
    if plan_count < 0 {
        return Err(format!(
            "unsupported payload sync negative plan count: {plan_count}"
        ));
    }
    for _ in 0..plan_count {
        skip_entity_build_plan(&mut reader)?;
    }
    let rotation_bits = reader.read_u32()?;
    let shield_bits = reader.read_u32()?;
    let spawned_by_core = reader.read_bool()?;
    let stack_item_id = reader.read_i16()?;
    let stack_amount = reader.read_i32()?;
    let status_count = reader.read_i32()?;
    consume_entity_status_entries(&mut reader, status_count, content_header, "payload sync")?;
    let snapshot = EntityPayloadSyncSnapshot {
        abilities_len,
        ammo_bits,
        controller_type,
        controller_value,
        elevation_bits,
        flag_bits,
        health_bits,
        is_shooting,
        mine_tile_pos,
        mount_count,
        payload_count,
        plan_count,
        rotation_bits,
        shield_bits,
        spawned_by_core,
        stack_item_id,
        stack_amount,
        status_count,
        team_id: reader.read_u8()?,
        unit_type_id: reader.read_i16()?,
        update_building: reader.read_bool()?,
        vel_x_bits: reader.read_u32()?,
        vel_y_bits: reader.read_u32()?,
        x_bits: reader.read_u32()?,
        y_bits: reader.read_u32()?,
    };
    if !snapshot.x().is_finite() || !snapshot.y().is_finite() {
        return Err("entity payload sync contained non-finite position".to_string());
    }
    Ok((snapshot, reader.position()))
}

pub fn parse_entity_building_tether_payload_sync_bytes(
    bytes: &[u8],
) -> Result<(EntityBuildingTetherPayloadSyncSnapshot, usize), String> {
    parse_entity_building_tether_payload_sync_bytes_with_content_header_option(None, bytes)
}

pub fn parse_entity_building_tether_payload_sync_bytes_with_content_header(
    content_header: &[ContentHeaderEntry],
    bytes: &[u8],
) -> Result<(EntityBuildingTetherPayloadSyncSnapshot, usize), String> {
    parse_entity_building_tether_payload_sync_bytes_with_content_header_option(
        Some(content_header),
        bytes,
    )
}

fn parse_entity_building_tether_payload_sync_bytes_with_content_header_option(
    content_header: Option<&[ContentHeaderEntry]>,
    bytes: &[u8],
) -> Result<(EntityBuildingTetherPayloadSyncSnapshot, usize), String> {
    let mut reader = Reader::new(bytes);
    let abilities_len = reader.read_u8()?;
    reader.skip_bytes(usize::from(abilities_len).saturating_mul(4))?;
    let ammo_bits = reader.read_u32()?;
    let building_pos = reader.read_i32()?;
    let (controller_type, controller_value) = skip_entity_unit_controller(&mut reader)?;
    let elevation_bits = reader.read_u32()?;
    let flag_bits = reader.read_u64()?;
    let health_bits = reader.read_u32()?;
    let is_shooting = reader.read_bool()?;
    let mine_tile_pos = reader.read_i32()?;
    let mount_count = reader.read_u8()?;
    reader.skip_bytes(usize::from(mount_count).saturating_mul(9))?;
    let payload_count = reader.read_i32()?;
    if payload_count < 0 {
        return Err(format!(
            "unsupported tether payload sync negative payload count: {payload_count}"
        ));
    }
    consume_entity_payload_entries(
        &mut reader,
        payload_count,
        content_header,
        "tether payload sync",
    )?;
    let plan_count = reader.read_i32()?;
    if plan_count < 0 {
        return Err(format!(
            "unsupported tether payload sync negative plan count: {plan_count}"
        ));
    }
    for _ in 0..plan_count {
        skip_entity_build_plan(&mut reader)?;
    }
    let rotation_bits = reader.read_u32()?;
    let shield_bits = reader.read_u32()?;
    let spawned_by_core = reader.read_bool()?;
    let stack_item_id = reader.read_i16()?;
    let stack_amount = reader.read_i32()?;
    let status_count = reader.read_i32()?;
    consume_entity_status_entries(
        &mut reader,
        status_count,
        content_header,
        "tether payload sync",
    )?;
    let snapshot = EntityBuildingTetherPayloadSyncSnapshot {
        abilities_len,
        ammo_bits,
        building_pos,
        controller_type,
        controller_value,
        elevation_bits,
        flag_bits,
        health_bits,
        is_shooting,
        mine_tile_pos,
        mount_count,
        payload_count,
        plan_count,
        rotation_bits,
        shield_bits,
        spawned_by_core,
        stack_item_id,
        stack_amount,
        status_count,
        team_id: reader.read_u8()?,
        unit_type_id: reader.read_i16()?,
        update_building: reader.read_bool()?,
        vel_x_bits: reader.read_u32()?,
        vel_y_bits: reader.read_u32()?,
        x_bits: reader.read_u32()?,
        y_bits: reader.read_u32()?,
    };
    if !snapshot.x().is_finite() || !snapshot.y().is_finite() {
        return Err("entity tether payload sync contained non-finite position".to_string());
    }
    Ok((snapshot, reader.position()))
}

