#[derive(Debug, Clone, Copy)]
pub struct WorldGrid<'a> {
    model: &'a WorldModel,
}

impl WorldModel {
    pub fn tile_count(&self) -> usize {
        self.width * self.height
    }

    pub fn grid(&self) -> WorldGrid<'_> {
        WorldGrid { model: self }
    }

    pub fn tile(&self, x: usize, y: usize) -> Option<&TileModel> {
        self.grid().tile(x, y)
    }

    pub fn tile_at_index(&self, tile_index: usize) -> Option<&TileModel> {
        self.grid().tile_at_index(tile_index)
    }

    pub fn building_center_at(&self, x: usize, y: usize) -> Option<&BuildingCenter> {
        self.grid().building_center_at(x, y)
    }

    pub fn building_center_by_index(&self, center_index: usize) -> Option<&BuildingCenter> {
        self.building_centers.get(center_index)
    }
}

impl<'a> WorldGrid<'a> {
    pub fn width(&self) -> usize {
        self.model.width
    }

    pub fn height(&self) -> usize {
        self.model.height
    }

    pub fn tile_count(&self) -> usize {
        self.model.tile_count()
    }

    pub fn contains(&self, x: usize, y: usize) -> bool {
        x < self.width() && y < self.height()
    }

    pub fn index(&self, x: usize, y: usize) -> Option<usize> {
        self.contains(x, y).then_some(x + y * self.width())
    }

    pub fn tile(&self, x: usize, y: usize) -> Option<&'a TileModel> {
        self.index(x, y)
            .and_then(|tile_index| self.tile_at_index(tile_index))
    }

    pub fn tile_at_index(&self, tile_index: usize) -> Option<&'a TileModel> {
        self.model.tiles.get(tile_index)
    }

    pub fn building_center_at(&self, x: usize, y: usize) -> Option<&'a BuildingCenter> {
        self.tile(x, y)
            .and_then(|tile| tile.building_center_index)
            .and_then(|center_index| self.model.building_centers.get(center_index))
    }

    pub fn iter_tiles(&self) -> impl Iterator<Item = &'a TileModel> {
        self.model.tiles.iter()
    }
}

fn summarize_payload_campaign_compound_model(model: &WorldModel) -> PayloadCampaignCompoundSummary {
    let mut constructors = Vec::new();
    let mut landing_pads = Vec::new();
    for center in &model.building_centers {
        match &center.building.parsed_tail {
            ParsedBuildingTail::Constructor(constructor) => {
                constructors.push((center, constructor))
            }
            ParsedBuildingTail::LandingPad(landing_pad) => landing_pads.push((center, landing_pad)),
            _ => {}
        }
    }

    let mut lines = Vec::new();
    push_hex(
        &mut lines,
        "payloadCampaignCompound.constructors.count",
        constructors.len() as u32,
        8,
    );
    for (index, (center, constructor)) in constructors.iter().enumerate() {
        let prefix = format!("payloadCampaignCompound.constructors.{index}");
        push_hex(
            &mut lines,
            &format!("{prefix}.tileIndex"),
            center.tile_index as u32,
            8,
        );
        push_hex(&mut lines, &format!("{prefix}.x"), center.x as u32, 4);
        push_hex(&mut lines, &format!("{prefix}.y"), center.y as u32, 4);
        push_hex(
            &mut lines,
            &format!("{prefix}.blockId"),
            center.block_id as u32,
            4,
        );
        push_payload_block_summary_lines(&mut lines, &prefix, &constructor.payload_block);
        push_hex(
            &mut lines,
            &format!("{prefix}.tail.constructor.progressBits"),
            constructor.progress_bits,
            8,
        );
        let recipe_block_id = format_optional_item_id(constructor.recipe_block_id);
        push_str(
            &mut lines,
            &format!("{prefix}.tail.constructor.recipeBlockId"),
            &recipe_block_id,
        );
    }

    push_hex(
        &mut lines,
        "payloadCampaignCompound.landingPads.count",
        landing_pads.len() as u32,
        8,
    );
    for (index, (center, landing_pad)) in landing_pads.iter().enumerate() {
        let prefix = format!("payloadCampaignCompound.landingPads.{index}");
        push_hex(
            &mut lines,
            &format!("{prefix}.tileIndex"),
            center.tile_index as u32,
            8,
        );
        push_hex(&mut lines, &format!("{prefix}.x"), center.x as u32, 4);
        push_hex(&mut lines, &format!("{prefix}.y"), center.y as u32, 4);
        push_hex(
            &mut lines,
            &format!("{prefix}.blockId"),
            center.block_id as u32,
            4,
        );
        let config_item_id = format_optional_item_id(landing_pad.config_item_id);
        push_str(
            &mut lines,
            &format!("{prefix}.tail.landingPad.configItemId"),
            &config_item_id,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.tail.landingPad.priority"),
            landing_pad.priority as u32,
            8,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.tail.landingPad.cooldownBits"),
            landing_pad.cooldown_bits,
            8,
        );
        let arriving_item_id = format_optional_item_id(landing_pad.arriving_item_id);
        push_str(
            &mut lines,
            &format!("{prefix}.tail.landingPad.arrivingItemId"),
            &arriving_item_id,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.tail.landingPad.arrivingTimerBits"),
            landing_pad.arriving_timer_bits,
            8,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.tail.landingPad.liquidRemovedBits"),
            landing_pad.liquid_removed_bits,
            8,
        );
    }

    PayloadCampaignCompoundSummary { lines }
}

fn format_optional_item_id(value: Option<u16>) -> String {
    value
        .map(|value| format!("{:04x}", value))
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_revision(value: Option<u8>) -> String {
    value
        .map(|value| format!("{:02x}", value))
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_byte(value: Option<u8>) -> String {
    value
        .map(|value| format!("{:02x}", value))
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_len(value: Option<usize>) -> String {
    value
        .map(|value| format!("{:08x}", value))
        .unwrap_or_else(|| "none".to_string())
}

fn format_optional_sha256(value: Option<&str>) -> String {
    value
        .map(|value| value.to_string())
        .unwrap_or_else(|| "none".to_string())
}

fn format_mixed_content_ref(value: &MixedContentRefTailSnapshot) -> String {
    match (value.content_type, value.content_id) {
        (Some(content_type), Some(content_id)) => format!("{content_type:02x}:{content_id:04x}"),
        (Some(content_type), None) => format!("{content_type:02x}:none"),
        (None, _) => "none".to_string(),
    }
}

fn payload_snapshot_kind(
    snapshot: Option<&PayloadSnapshot>,
    payload_present: bool,
) -> &'static str {
    match snapshot {
        Some(PayloadSnapshot::Null) => "null",
        Some(PayloadSnapshot::Build(_)) => "build",
        Some(PayloadSnapshot::Unit(_)) => "unit",
        None if payload_present => "unknown",
        None => "null",
    }
}

fn building_tail_kind(parsed_tail: &ParsedBuildingTail) -> &'static str {
    match parsed_tail {
        ParsedBuildingTail::Empty => "empty",
        ParsedBuildingTail::Conveyor(_) => "conveyor",
        ParsedBuildingTail::StackConveyor(_) => "stackConveyor",
        ParsedBuildingTail::Core(_) => "core",
        ParsedBuildingTail::UnitFactory(_) => "unitFactory",
        ParsedBuildingTail::Reconstructor(_) => "reconstructor",
        ParsedBuildingTail::NullableItemRef(_) => "nullableItemRef",
        ParsedBuildingTail::ItemBridge(_) => "itemBridge",
        ParsedBuildingTail::BufferedItemBridge(_) => "bufferedItemBridge",
        ParsedBuildingTail::MassDriver(_) => "massDriver",
        ParsedBuildingTail::Junction(_) => "junction",
        ParsedBuildingTail::SorterLegacy(_) => "sorterLegacy",
        ParsedBuildingTail::Turret(_) => "turret",
        ParsedBuildingTail::ItemTurret(_) => "itemTurret",
        ParsedBuildingTail::ContinuousTurret(_) => "continuousTurret",
        ParsedBuildingTail::BuildTurret(_) => "buildTurret",
        ParsedBuildingTail::PayloadLoader(_) => "payloadLoader",
        ParsedBuildingTail::PayloadSource(_) => "payloadSource",
        ParsedBuildingTail::PayloadRouter(_) => "payloadRouter",
        ParsedBuildingTail::PayloadMassDriver(_) => "payloadMassDriver",
        ParsedBuildingTail::BlockProducer(_) => "blockProducer",
        ParsedBuildingTail::Constructor(_) => "constructor",
        ParsedBuildingTail::UnitAssembler(_) => "unitAssembler",
        ParsedBuildingTail::OneF32(_) => "oneF32",
        ParsedBuildingTail::OneI8(_) => "oneI8",
        ParsedBuildingTail::OneI32(_) => "oneI32",
        ParsedBuildingTail::OneBool(_) => "oneBool",
        ParsedBuildingTail::OneF32Bool(_) => "oneF32Bool",
        ParsedBuildingTail::TwoF32(_) => "twoF32",
        ParsedBuildingTail::TwoF32I32(_) => "twoF32I32",
        ParsedBuildingTail::ThreeF32(_) => "threeF32",
        ParsedBuildingTail::FiveF32(_) => "fiveF32",
        ParsedBuildingTail::LandingPad(_) => "landingPad",
        ParsedBuildingTail::Message(_) => "message",
        ParsedBuildingTail::DuctUnloader(_) => "ductUnloader",
        ParsedBuildingTail::Memory(_) => "memory",
        ParsedBuildingTail::Canvas(_) => "canvas",
        ParsedBuildingTail::Unknown => "unknown",
    }
}

pub fn parse_world_load_goldens(compressed: &[u8]) -> Result<WorldLoadSummary, String> {
    let bundle = parse_world_bundle(compressed)?;
    let unknown_coverage = bundle.unknown_coverage_summary();
    let mut tag_bytes = Vec::new();
    for (key, value) in &bundle.tag_pairs {
        write_java_utf(&mut tag_bytes, key)?;
        write_java_utf(&mut tag_bytes, value)?;
    }

    let mut content_bytes = Vec::new();
    for entry in &bundle.content_header {
        content_bytes.push(entry.content_type);
        content_bytes.extend_from_slice(&(entry.names.len() as u16).to_be_bytes());
        for name in &entry.names {
            write_java_utf(&mut content_bytes, name)?;
        }
    }

    let mut patch_bytes = Vec::new();
    for patch in &bundle.patches {
        patch_bytes.extend_from_slice(patch);
    }

    let floor_bytes = bundle.floor_region_bytes.clone();
    let block_bytes = bundle.block_region_bytes.clone();
    let team_bytes = bundle.team_region_bytes.clone();
    let marker_bytes = bundle.marker_region_bytes.clone();
    let custom_bytes = bundle.custom_region_bytes.clone();

    let mut lines = Vec::new();
    push_hex(
        &mut lines,
        "compressed.length",
        bundle.compressed.len() as u32,
        8,
    );
    push_str(
        &mut lines,
        "compressed.sha256",
        &sha256_hex(&bundle.compressed),
    );
    push_hex(
        &mut lines,
        "inflated.length",
        bundle.inflated.len() as u32,
        8,
    );
    push_str(&mut lines, "inflated.sha256", &sha256_hex(&bundle.inflated));
    push_hex(
        &mut lines,
        "rules.length",
        bundle.rules_json.as_bytes().len() as u32,
        8,
    );
    push_str(
        &mut lines,
        "rules.sha256",
        &sha256_hex(bundle.rules_json.as_bytes()),
    );
    push_hex(
        &mut lines,
        "mapLocales.length",
        bundle.map_locales_json.as_bytes().len() as u32,
        8,
    );
    push_str(
        &mut lines,
        "mapLocales.sha256",
        &sha256_hex(bundle.map_locales_json.as_bytes()),
    );
    push_hex(&mut lines, "tags.count", bundle.tag_pairs.len() as u32, 4);
    push_str(&mut lines, "tags.sha256", &sha256_hex(&tag_bytes));
    push_hex(&mut lines, "wave", bundle.wave as u32, 8);
    push_hex(&mut lines, "wavetime.bits", bundle.wavetime_bits, 8);
    push_str(
        &mut lines,
        "tick.bits",
        &format!("{:016x}", bundle.tick_bits),
    );
    push_str(&mut lines, "rand0", &format!("{:016x}", bundle.rand0));
    push_str(&mut lines, "rand1", &format!("{:016x}", bundle.rand1));
    push_hex(&mut lines, "player.id", bundle.player.id as u32, 8);
    push_hex(
        &mut lines,
        "player.revision",
        bundle.player.revision as u32,
        4,
    );
    push_str(
        &mut lines,
        "player.admin",
        if bundle.player.admin { "1" } else { "0" },
    );
    push_str(
        &mut lines,
        "player.boosting",
        if bundle.player.boosting { "1" } else { "0" },
    );
    push_hex(&mut lines, "player.color", bundle.player.color_rgba, 8);
    push_hex(
        &mut lines,
        "player.command",
        bundle.player.command_id as u32,
        2,
    );
    push_hex(&mut lines, "player.mouseX", bundle.player.mouse_x_bits, 8);
    push_hex(&mut lines, "player.mouseY", bundle.player.mouse_y_bits, 8);
    push_str(
        &mut lines,
        "player.nameSha256",
        &sha256_hex(bundle.player.name.as_bytes()),
    );
    push_hex(
        &mut lines,
        "player.selectedBlock",
        bundle.player.selected_block_id as u32,
        4,
    );
    push_hex(
        &mut lines,
        "player.selectedRotation",
        bundle.player.selected_rotation,
        8,
    );
    push_str(
        &mut lines,
        "player.shooting",
        if bundle.player.shooting { "1" } else { "0" },
    );
    push_hex(&mut lines, "player.team", bundle.player.team_id as u32, 2);
    push_str(
        &mut lines,
        "player.typing",
        if bundle.player.typing { "1" } else { "0" },
    );
    push_hex(
        &mut lines,
        "player.unitType",
        bundle.player.unit_kind as u32,
        2,
    );
    push_hex(&mut lines, "player.unitValue", bundle.player.unit_value, 8);
    push_hex(&mut lines, "player.x", bundle.player.x_bits, 8);
    push_hex(&mut lines, "player.y", bundle.player.y_bits, 8);
    push_hex(
        &mut lines,
        "contentHeader.mappedTypes",
        bundle.content_header.len() as u32,
        2,
    );
    push_str(
        &mut lines,
        "contentHeader.sha256",
        &sha256_hex(&content_bytes),
    );
    push_hex(&mut lines, "patches.count", bundle.patches.len() as u32, 2);
    push_str(&mut lines, "patches.sha256", &sha256_hex(&patch_bytes));
    push_hex(&mut lines, "map.width", bundle.world.width as u32, 4);
    push_hex(&mut lines, "map.height", bundle.world.height as u32, 4);
    push_hex(&mut lines, "map.floorRuns", bundle.floor_runs as u32, 8);
    push_str(&mut lines, "map.floor.sha256", &sha256_hex(&floor_bytes));
    push_hex(&mut lines, "map.blockRuns", bundle.block_runs as u32, 8);
    push_hex(
        &mut lines,
        "map.buildingCenters",
        bundle.world.building_centers.len() as u32,
        8,
    );
    push_hex(
        &mut lines,
        "map.buildingCenters.unknownTailCount",
        unknown_coverage.building_tail_unknown_count as u32,
        8,
    );
    push_hex(
        &mut lines,
        "map.dataTiles",
        bundle.world.data_tiles as u32,
        8,
    );
    push_str(&mut lines, "map.block.sha256", &sha256_hex(&block_bytes));
    push_hex(
        &mut lines,
        "teamBlocks.teamCount",
        bundle.team_plan_groups.len() as u32,
        8,
    );
    push_hex(
        &mut lines,
        "teamBlocks.totalPlans",
        bundle.world.total_plans as u32,
        8,
    );
    push_str(&mut lines, "teamBlocks.sha256", &sha256_hex(&team_bytes));
    push_hex(&mut lines, "markers.count", bundle.marker_count as u32, 8);
    push_hex(
        &mut lines,
        "markers.unknownModelCount",
        unknown_coverage.marker_unknown_count as u32,
        8,
    );
    push_str(&mut lines, "markers.sha256", &sha256_hex(&marker_bytes));
    push_hex(
        &mut lines,
        "customChunks.count",
        bundle.custom_chunks.len() as u32,
        8,
    );
    push_hex(
        &mut lines,
        "customChunks.unknownCount",
        unknown_coverage.custom_chunk_unknown_count as u32,
        8,
    );
    push_str(
        &mut lines,
        "customChunks.sha256",
        &sha256_hex(&custom_bytes),
    );
    push_hex(&mut lines, "tail.length", bundle.tail.len() as u32, 8);
    push_str(&mut lines, "tail.sha256", &sha256_hex(&bundle.tail));

    Ok(WorldLoadSummary {
        lines,
        unknown_coverage,
    })
}

pub fn parse_world_model(compressed: &[u8]) -> Result<WorldModel, String> {
    Ok(parse_world_bundle(compressed)?.world)
}

pub fn parse_logic_processor_compressed_config_summary(
    compressed: &[u8],
) -> Result<LogicProcessorCompressedConfigSummary, String> {
    let inflated = inflate_zlib(compressed)?;
    let mut reader = Reader::new(&inflated);

    let version = reader.read_u8()?;
    let code_len = read_non_negative_i32_len("logic processor code length", reader.read_i32()?)?;
    let code = String::from_utf8(reader.read_exact_vec(code_len)?)
        .map_err(|error| format!("invalid UTF-8 logic processor code: {error}"))?;
    let link_count = read_non_negative_i32_len("logic processor link count", reader.read_i32()?)?;

    let links = if version == 0 {
        for _ in 0..link_count {
            reader.read_i32()?;
        }
        Vec::new()
    } else {
        let mut links = Vec::with_capacity(link_count);
        for _ in 0..link_count {
            links.push(LogicProcessorCompressedLinkSummary {
                name: read_java_modified_utf(&mut reader)?,
                x: reader.read_i16()?,
                y: reader.read_i16()?,
            });
        }
        links
    };

    if reader.remaining_len() != 0 {
        return Err(format!(
            "unexpected trailing logic processor config bytes: {}",
            reader.remaining_len()
        ));
    }

    Ok(LogicProcessorCompressedConfigSummary {
        version,
        code,
        link_count,
        links,
    })
}

pub fn generate_team_plan_sample_bytes() -> Vec<u8> {
    let mut out = Vec::new();
    out.extend_from_slice(&1u32.to_be_bytes());
    out.extend_from_slice(&1u32.to_be_bytes());
    out.extend_from_slice(&1u32.to_be_bytes());
    out.extend_from_slice(&1i16.to_be_bytes());
    out.extend_from_slice(&2i16.to_be_bytes());
    out.extend_from_slice(&1i16.to_be_bytes());
    out.extend_from_slice(&0x0101u16.to_be_bytes());
    out.push(7);
    out.extend_from_slice(&3i32.to_be_bytes());
    out.extend_from_slice(&4i32.to_be_bytes());
    out
}

