pub fn generate_static_fog_sample_bytes() -> Vec<u8> {
    let width = 4usize;
    let height = 3usize;
    let len = width * height;
    let mut out = Vec::new();
    out.push(2);
    out.extend_from_slice(&(width as u16).to_be_bytes());
    out.extend_from_slice(&(height as u16).to_be_bytes());

    for (team_id, discovered_indices) in [
        (1u8, vec![0usize, 1, 4, 5, 10]),
        (5u8, vec![3usize, 7, 8, 9, 11]),
    ] {
        let mut discovered = vec![false; len];
        for index in discovered_indices {
            discovered[index] = true;
        }

        out.push(team_id);
        write_static_fog_runs(&mut out, &discovered);
    }

    out
}

