pub fn parse_world_enter_component_goldens(
    compressed: &[u8],
) -> Result<WorldEnterComponentSummary, String> {
    let lines = parse_world_enter_init_state_goldens(compressed)?
        .lines
        .into_iter()
        .filter_map(|(key, value)| {
            key.strip_prefix("state.component.")
                .map(|suffix| (format!("component.{suffix}"), value))
        })
        .collect();
    Ok(WorldEnterComponentSummary { lines })
}

