fn parse_payload_seq_snapshot(reader: &mut Reader<'_>) -> Result<PayloadSeqSnapshot, String> {
    let amount = reader.read_i16()?;
    let (legacy_format, entry_count) = if amount >= 0 {
        (true, amount as usize)
    } else {
        (false, (-amount) as usize)
    };
    let mut entries = Vec::with_capacity(entry_count);
    for _ in 0..entry_count {
        let (content_type, content_id) = if legacy_format {
            (BLOCK_CONTENT_TYPE, reader.read_i16()?)
        } else {
            (reader.read_u8()?, reader.read_i16()?)
        };
        let amount = reader.read_i32()?;
        entries.push(PayloadSeqEntrySnapshot {
            content_type,
            content_id,
            amount,
        });
    }
    Ok(PayloadSeqSnapshot {
        legacy_format,
        entry_count,
        entries,
    })
}

