fn parse_unit_factory_tail_snapshot(
    content_header: &[ContentHeaderEntry],
    revision: u8,
    tail_bytes: &[u8],
) -> Result<UnitFactoryTailSnapshot, String> {
    let mut reader = Reader::new(tail_bytes);
    let payload_block = parse_payload_block_tail_snapshot(
        content_header,
        &mut reader,
        "unit-factory",
        |remainder| validate_unit_factory_remainder(remainder, revision),
    )?;
    let progress_bits = reader.read_u32()?;
    let current_plan = reader.read_i16()?;
    let command_pos = if revision >= 2 {
        parse_nullable_vec2_tail_snapshot(&mut reader)?
    } else {
        nan_nullable_vec2_tail()
    };
    let command_id = if revision >= 3 {
        let command = reader.read_u8()?;
        (command != 255).then_some(command)
    } else {
        None
    };

    if !reader.remaining_bytes().is_empty() {
        return Err(format!(
            "unexpected unit factory tail remainder: {} bytes",
            reader.remaining_bytes().len()
        ));
    }

    Ok(UnitFactoryTailSnapshot {
        payload_block,
        progress_bits,
        current_plan,
        command_pos,
        command_id,
    })
}

