fn parse_nullable_item_ref_tail_snapshot(
    block_name: Option<&str>,
    revision: u8,
    tail_bytes: &[u8],
) -> Result<NullableItemRefTailSnapshot, String> {
    let mut reader = Reader::new(tail_bytes);
    let item_id = match block_name {
        Some("unloader") | Some("liquid-source") if revision == 0 => {
            let id = reader.read_i8()? as i16;
            (id >= 0).then_some(id as u16)
        }
        Some("unit-cargo-unload-point") => {
            let id = reader.read_i16()?;
            let _stale = reader.read_bool()?;
            (id >= 0).then_some(id as u16)
        }
        _ => {
            let id = reader.read_i16()?;
            (id >= 0).then_some(id as u16)
        }
    };

    if !reader.remaining_bytes().is_empty() {
        return Err(format!(
            "unexpected nullable item ref tail remainder: {} bytes",
            reader.remaining_bytes().len()
        ));
    }

    Ok(NullableItemRefTailSnapshot { item_id })
}

fn read_nullable_item_id(reader: &mut Reader<'_>) -> Result<Option<u16>, String> {
    let id = reader.read_i16()?;
    Ok((id >= 0).then_some(id as u16))
}

fn parse_building_base_snapshot(reader: &mut Reader<'_>) -> Result<BuildingBaseSnapshot, String> {
    let health_bits = reader.read_u32()?;
    let rot = reader.read_u8()?;
    let team_id = reader.read_u8()?;
    let rotation = rot & 0b0111_1111;

    if (rot & 0b1000_0000) == 0 {
        return Ok(BuildingBaseSnapshot {
            health_bits,
            rotation,
            team_id,
            legacy: true,
            save_version: None,
            enabled: None,
            module_bitmask: None,
            item_module: None,
            power_module: None,
            liquid_module: None,
            time_scale_bits: None,
            time_scale_duration_bits: None,
            last_disabler_pos: None,
            legacy_consume_connected: None,
            efficiency: None,
            optional_efficiency: None,
            visible_flags: None,
        });
    }

    let save_version = reader.read_u8()?;
    let enabled = if save_version >= 1 {
        Some(reader.read_bool()?)
    } else {
        None
    };

    if save_version < 2 {
        return Ok(BuildingBaseSnapshot {
            health_bits,
            rotation,
            team_id,
            legacy: false,
            save_version: Some(save_version),
            enabled,
            module_bitmask: None,
            item_module: None,
            power_module: None,
            liquid_module: None,
            time_scale_bits: None,
            time_scale_duration_bits: None,
            last_disabler_pos: None,
            legacy_consume_connected: None,
            efficiency: None,
            optional_efficiency: None,
            visible_flags: None,
        });
    }

    let module_bitmask = reader.read_u8()?;
    let item_module = if (module_bitmask & 1) != 0 {
        Some(parse_building_item_module_snapshot(reader)?)
    } else {
        None
    };
    let power_module = if (module_bitmask & (1 << 1)) != 0 {
        Some(parse_building_power_module_snapshot(reader)?)
    } else {
        None
    };
    let liquid_module = if (module_bitmask & (1 << 2)) != 0 {
        Some(parse_building_liquid_module_snapshot(reader)?)
    } else {
        None
    };
    let (time_scale_bits, time_scale_duration_bits) = if (module_bitmask & (1 << 4)) != 0 {
        (Some(reader.read_u32()?), Some(reader.read_u32()?))
    } else {
        (None, None)
    };
    let last_disabler_pos = if (module_bitmask & (1 << 5)) != 0 {
        Some(reader.read_i32()?)
    } else {
        None
    };
    let legacy_consume_connected = if save_version <= 2 {
        Some(reader.read_bool()?)
    } else {
        None
    };
    let (efficiency, optional_efficiency) = if save_version >= 3 {
        (Some(reader.read_u8()?), Some(reader.read_u8()?))
    } else {
        (None, None)
    };
    let visible_flags = if save_version == 4 {
        Some(reader.read_u64()?)
    } else {
        None
    };

    Ok(BuildingBaseSnapshot {
        health_bits,
        rotation,
        team_id,
        legacy: false,
        save_version: Some(save_version),
        enabled,
        module_bitmask: Some(module_bitmask),
        item_module,
        power_module,
        liquid_module,
        time_scale_bits,
        time_scale_duration_bits,
        last_disabler_pos,
        legacy_consume_connected,
        efficiency,
        optional_efficiency,
        visible_flags,
    })
}

