fn parse_save_custom_chunks_region(bytes: &[u8]) -> Result<Vec<CustomChunkEntry>, String> {
    let mut reader = Reader::new(bytes);
    let custom_chunk_count = reader.read_u32()? as usize;
    let available_bytes = reader.remaining_len();
    let max_custom_chunk_count = available_bytes / 6;
    if custom_chunk_count > max_custom_chunk_count {
        return Err(format!(
            "save custom region declares too many chunks: count={} remaining={}",
            custom_chunk_count, available_bytes
        ));
    }
    let mut custom_chunks = Vec::with_capacity(custom_chunk_count);
    for _ in 0..custom_chunk_count {
        let name = reader.read_java_utf()?;
        let chunk_len = reader.read_u32()? as usize;
        let remaining_bytes = reader.remaining_len();
        if chunk_len > remaining_bytes {
            return Err(format!(
                "save custom chunk {:?} length {} exceeds remaining bytes {}",
                name, chunk_len, remaining_bytes
            ));
        }
        let chunk_bytes = reader.read_exact_vec(chunk_len)?;
        let parsed = parse_known_custom_chunk(&name, &chunk_bytes)?;
        custom_chunks.push(CustomChunkEntry {
            name,
            chunk_len,
            chunk_sha256: sha256_hex(&chunk_bytes),
            chunk_bytes,
            parsed,
        });
    }

    if !reader.remaining_bytes().is_empty() {
        return Err(format!(
            "unexpected trailing bytes after save custom region: {}",
            reader.remaining_bytes().len()
        ));
    }

    Ok(custom_chunks)
}

fn parse_msav_envelope_from_inflated(
    inflated: &[u8],
    compressed_length: usize,
    zlib_header: MsavZlibHeader,
) -> Result<(MsavEnvelopeObservation, Reader<'_>), String> {
    if inflated.len() < MSAV_HEADER.len() + 4 {
        return Err(format!(
            "inflated .msav envelope too short: expected at least {} bytes, got {}",
            MSAV_HEADER.len() + 4,
            inflated.len()
        ));
    }

    let mut reader = Reader::new(&inflated);
    let header = reader
        .read_exact_vec(MSAV_HEADER.len())?
        .try_into()
        .map_err(|_| "failed to read .msav header bytes".to_string())?;
    if header != MSAV_HEADER {
        return Err(format!(
            "unexpected .msav header: expected {:?}, got {:?}",
            MSAV_HEADER, header
        ));
    }

    let save_version = reader.read_i32()?;
    let body_start = reader.position();
    let leading_region_length = if body_start + 4 <= inflated.len() {
        let length_bytes: [u8; 4] = inflated[body_start..body_start + 4]
            .try_into()
            .map_err(|_| "failed to read leading region length".to_string())?;
        Some(u32::from_be_bytes(length_bytes))
    } else {
        None
    };

    Ok((
        MsavEnvelopeObservation {
            compressed_length,
            inflated_length: inflated.len(),
            body_length: inflated.len() - (MSAV_HEADER.len() + 4),
            zlib_header,
            header,
            save_version,
            leading_region_length,
        },
        reader,
    ))
}

fn msav_region_names(save_version: i32) -> Result<&'static [&'static str], String> {
    match save_version {
        1..=6 => Ok(&["meta", "content", "map", "entities"]),
        7 => Ok(&["meta", "content", "map", "entities", "custom"]),
        8..=10 => Ok(&["meta", "content", "map", "entities", "markers", "custom"]),
        11 => Ok(&[
            "meta", "content", "patches", "map", "entities", "markers", "custom",
        ]),
        _ => Err(format!(
            "unsupported .msav save version for passive parsing: {}",
            save_version
        )),
    }
}

fn read_msav_region_observation(
    reader: &mut Reader<'_>,
    name: &'static str,
) -> Result<MsavRegionObservation, String> {
    let chunk_length = reader.read_u32()? as usize;
    let chunk_bytes = reader.read_exact_vec(chunk_length)?;
    Ok(MsavRegionObservation {
        name,
        chunk_length,
        chunk_sha256: sha256_hex(&chunk_bytes),
        chunk_bytes,
    })
}

fn parse_save_entity_remap_table(
    reader: &mut Reader<'_>,
) -> Result<(usize, Vec<SaveEntityRemapEntry>, Vec<u8>), String> {
    let start = reader.position();
    let remap_count = reader.read_u16()? as usize;
    let mut remap_entries = Vec::with_capacity(remap_count);
    for _ in 0..remap_count {
        remap_entries.push(SaveEntityRemapEntry {
            custom_id: reader.read_u16()?,
            name: reader.read_java_utf()?,
        });
    }
    let end = reader.position();
    Ok((
        remap_count,
        remap_entries,
        reader.slice(start, end).to_vec(),
    ))
}

fn synthetic_legacy_entity_id(index: usize) -> Result<i32, String> {
    let sequence = i32::try_from(index)
        .map_err(|_| format!("legacy save entity index too large for synthetic id: {index}"))?;
    sequence
        .checked_add(1)
        .map(|value| -value)
        .ok_or_else(|| format!("legacy save entity index too large for synthetic id: {index}"))
}

fn read_save_chunk_len(reader: &mut Reader<'_>, save_version: i32) -> Result<usize, String> {
    if save_version >= 10 {
        Ok(reader.read_u32()? as usize)
    } else {
        Ok(reader.read_u16()? as usize)
    }
}

fn checked_tile_count(width: usize, height: usize, label: &str) -> Result<usize, String> {
    width.checked_mul(height).ok_or_else(|| {
        format!(
            "{label} dimensions overflow: width={} height={}",
            width, height
        )
    })
}

fn parse_save_world_entity_chunks(
    reader: &mut Reader<'_>,
    save_version: i32,
    remap_entries: &[SaveEntityRemapEntry],
) -> Result<(usize, Vec<SaveEntityChunkObservation>, Vec<u8>), String> {
    let start = reader.position();
    let world_entity_count = reader.read_u32()? as usize;
    let remap_names = effective_remap_names_first_seen(remap_entries);
    let mut entity_chunks = Vec::with_capacity(world_entity_count);

    for index in 0..world_entity_count {
        let chunk_len = read_save_chunk_len(reader, save_version)?;
        let chunk_bytes = reader.read_exact_vec(chunk_len)?;
        let mut chunk_reader = Reader::new(&chunk_bytes);
        let class_id = chunk_reader.read_u8().map_err(|error| {
            format!("failed to read save entity chunk {index} class id: {error}")
        })?;
        let entity_id = chunk_reader.read_i32().map_err(|error| {
            format!("failed to read save entity chunk {index} entity id: {error}")
        })?;
        let body_bytes = chunk_reader.remaining_bytes();
        entity_chunks.push(SaveEntityChunkObservation {
            chunk_len,
            chunk_sha256: sha256_hex(&chunk_bytes),
            class_id,
            custom_name: remap_names.get(&(class_id as u16)).cloned(),
            entity_id,
            body_len: body_bytes.len(),
            body_sha256: sha256_hex(&body_bytes),
            body_bytes,
            chunk_bytes,
        });
    }

    let end = reader.position();
    Ok((
        world_entity_count,
        entity_chunks,
        reader.slice(start, end).to_vec(),
    ))
}

fn parse_save_world_entity_chunks_without_ids(
    reader: &mut Reader<'_>,
    remap_entries: &[SaveEntityRemapEntry],
) -> Result<(usize, Vec<SaveEntityChunkObservation>, Vec<u8>), String> {
    let start = reader.position();
    let world_entity_count = reader.read_u32()? as usize;
    let remap_names = effective_remap_names_first_seen(remap_entries);
    let mut entity_chunks = Vec::with_capacity(world_entity_count);

    for index in 0..world_entity_count {
        let chunk_len = reader.read_u16()? as usize;
        let chunk_bytes = reader.read_exact_vec(chunk_len)?;
        let mut chunk_reader = Reader::new(&chunk_bytes);
        let class_id = chunk_reader.read_u8().map_err(|error| {
            format!("failed to read legacy save entity chunk {index} class id: {error}")
        })?;
        let body_bytes = chunk_reader.remaining_bytes();
        let entity_id = synthetic_legacy_entity_id(index)?;
        entity_chunks.push(SaveEntityChunkObservation {
            chunk_len,
            chunk_sha256: sha256_hex(&chunk_bytes),
            class_id,
            custom_name: remap_names.get(&(class_id as u16)).cloned(),
            entity_id,
            body_len: body_bytes.len(),
            body_sha256: sha256_hex(&body_bytes),
            body_bytes,
            chunk_bytes,
        });
    }

    let end = reader.position();
    Ok((
        world_entity_count,
        entity_chunks,
        reader.slice(start, end).to_vec(),
    ))
}

fn parse_legacy_save_entity_groups(
    reader: &mut Reader<'_>,
) -> Result<(usize, Vec<SaveEntityChunkObservation>, Vec<u8>), String> {
    let start = reader.position();
    let group_count = reader.read_u8()? as usize;
    let max_group_count = reader.remaining_len() / 4;
    if group_count > max_group_count && group_count > 0 {
        return Err(format!(
            "legacy save entity region declares too many groups: count={} remaining={}",
            group_count,
            reader.remaining_len()
        ));
    }

    let mut entity_chunks = Vec::new();
    for _ in 0..group_count {
        let amount = reader.read_u32()? as usize;
        for _ in 0..amount {
            let chunk_len = reader.read_u16()? as usize;
            let chunk_bytes = reader.read_exact_vec(chunk_len)?;
            let entity_id = synthetic_legacy_entity_id(entity_chunks.len())?;
            entity_chunks.push(SaveEntityChunkObservation {
                chunk_len,
                chunk_sha256: sha256_hex(&chunk_bytes),
                class_id: u8::MAX,
                custom_name: None,
                entity_id,
                body_len: chunk_bytes.len(),
                body_sha256: sha256_hex(&chunk_bytes),
                body_bytes: chunk_bytes.clone(),
                chunk_bytes,
            });
        }
    }

    let end = reader.position();
    Ok((
        entity_chunks.len(),
        entity_chunks,
        reader.slice(start, end).to_vec(),
    ))
}

pub fn parse_world_bundle(compressed: &[u8]) -> Result<WorldBundle, String> {
    let inflated = inflate_zlib(compressed)?;
    let mut reader = Reader::new(&inflated);

    let rules_json = reader.read_java_utf()?;
    let map_locales_json = reader.read_java_utf()?;

    let tag_count = reader.read_u16()? as usize;
    let mut tag_pairs = Vec::with_capacity(tag_count);
    let mut seen_tag_keys = HashSet::with_capacity(tag_count);
    for _ in 0..tag_count {
        let key = reader.read_java_utf()?;
        if !seen_tag_keys.insert(key.clone()) {
            return Err(format!("duplicate tag key in world bundle: {key}"));
        }
        tag_pairs.push((key, reader.read_java_utf()?));
    }

    let wave = reader.read_i32()?;
    let wavetime_bits = reader.read_u32()?;
    let tick_bits = reader.read_u64()?;
    let rand0 = reader.read_u64()?;
    let rand1 = reader.read_u64()?;
    let player_id = reader.read_i32()?;

    let player = ParsedPlayer {
        id: player_id,
        revision: reader.read_u16()?,
        admin: reader.read_bool()?,
        boosting: reader.read_bool()?,
        color_rgba: reader.read_u32()?,
        command_id: reader.read_u8()?,
        mouse_x_bits: reader.read_u32()?,
        mouse_y_bits: reader.read_u32()?,
        name: reader.read_typeio_string()?,
        selected_block_id: reader.read_u16()?,
        selected_rotation: reader.read_u32()?,
        shooting: reader.read_bool()?,
        team_id: reader.read_u8()?,
        typing: reader.read_bool()?,
        unit_kind: reader.read_u8()?,
        unit_value: reader.read_u32()?,
        x_bits: reader.read_u32()?,
        y_bits: reader.read_u32()?,
    };

    let mapped_types = reader.read_u8()? as usize;
    let mut content_header = Vec::with_capacity(mapped_types);
    let mut seen_content_types = HashSet::with_capacity(mapped_types);
    for _ in 0..mapped_types {
        let content_type = reader.read_u8()?;
        if !seen_content_types.insert(content_type) {
            return Err(format!(
                "duplicate content type in world bundle: {content_type}"
            ));
        }
        let total = reader.read_u16()? as usize;
        let mut names = Vec::with_capacity(total);
        for _ in 0..total {
            names.push(reader.read_java_utf()?);
        }
        content_header.push(ContentHeaderEntry {
            content_type,
            names,
        });
    }

    let patch_count = reader.read_u8()? as usize;
    let mut patches = Vec::with_capacity(patch_count);
    for _ in 0..patch_count {
        let len = reader.read_u32()? as usize;
        patches.push(reader.read_exact_vec(len)?);
    }

    let width = reader.read_u16()? as usize;
    let height = reader.read_u16()? as usize;
    let tile_count = checked_tile_count(width, height, "world bundle")?;

    let mut floors = vec![0u16; tile_count];
    let mut overlays = vec![0u16; tile_count];
    let mut floor_region_bytes = Vec::new();
    let mut floor_runs = 0usize;
    let mut i = 0usize;
    while i < tile_count {
        let floor = reader.read_u16()?;
        let overlay = reader.read_u16()?;
        let consecutives = reader.read_u8()? as usize;
        let run_end = i.checked_add(consecutives).ok_or_else(|| {
            format!(
                "world bundle floor run overflows index space at tile {} with run length {}",
                i, consecutives
            )
        })?;
        if run_end >= tile_count {
            return Err(format!(
                "world bundle floor run overruns map bounds: start={} run_len={} tiles={}",
                i,
                consecutives + 1,
                tile_count
            ));
        }
        floor_region_bytes.extend_from_slice(&floor.to_be_bytes());
        floor_region_bytes.extend_from_slice(&overlay.to_be_bytes());
        floor_region_bytes.push(consecutives as u8);
        for j in i..=run_end {
            floors[j] = floor;
            overlays[j] = overlay;
        }
        floor_runs += 1;
        i = run_end + 1;
    }

    let mut blocks = vec![0u16; tile_count];
    let mut building_centers = Vec::new();
    let mut data_tiles = 0usize;
    let mut block_region_bytes = Vec::new();
    let mut block_runs = 0usize;
    let mut i = 0usize;
    while i < tile_count {
        let block = reader.read_u16()?;
        let packed = reader.read_u8()?;
        let had_entity = (packed & 1) != 0;
        let had_data = (packed & 4) != 0;
        let mut is_center = true;
        blocks[i] = block;
        block_region_bytes.extend_from_slice(&block.to_be_bytes());
        block_region_bytes.push(packed);

        if had_data {
            data_tiles += 1;
            let data = reader.read_u8()?;
            let floor_data = reader.read_u8()?;
            let overlay_data = reader.read_u8()?;
            let extra_data = reader.read_u32()?;
            block_region_bytes.push(data);
            block_region_bytes.push(floor_data);
            block_region_bytes.push(overlay_data);
            block_region_bytes.extend_from_slice(&extra_data.to_be_bytes());
        }

        if had_entity {
            is_center = reader.read_bool()?;
            block_region_bytes.push(u8::from(is_center));
        }

        if had_entity && is_center {
            let chunk_len = reader.read_u32()? as usize;
            let chunk = reader.read_exact_vec(chunk_len)?;
            let block_name = resolve_content_name(&content_header, BLOCK_CONTENT_TYPE, block);
            let building =
                parse_building_snapshot(&content_header, block_name, &chunk).map_err(|error| {
                    format!(
                    "failed to parse building center chunk at ({}, {}) for block {:04x} ({:?}): {}",
                    i % width,
                    i / width,
                    block,
                    block_name,
                    error
                )
                })?;
            block_region_bytes.extend_from_slice(&(chunk_len as u32).to_be_bytes());
            block_region_bytes.extend_from_slice(&chunk);
            building_centers.push(BuildingCenter {
                tile_index: i,
                x: i % width,
                y: i / width,
                block_id: block,
                chunk_len,
                chunk_bytes: chunk.clone(),
                chunk_sha256: sha256_hex(&chunk),
                building,
            });
        } else if !had_data && !had_entity {
            let consecutives = reader.read_u8()? as usize;
            let run_end = i.checked_add(consecutives).ok_or_else(|| {
                format!(
                    "world bundle block run overflows index space at tile {} with run length {}",
                    i, consecutives
                )
            })?;
            if run_end >= tile_count {
                return Err(format!(
                    "world bundle block run overruns map bounds: start={} run_len={} tiles={}",
                    i,
                    consecutives + 1,
                    tile_count
                ));
            }
            block_region_bytes.push(consecutives as u8);
            for j in (i + 1)..=run_end {
                blocks[j] = block;
            }
            i = run_end;
        }

        block_runs += 1;
        i += 1;
    }

    let TeamPlanParseResult {
        team_count,
        total_plans,
        team_ids,
        team_plan_counts,
        team_plan_groups,
        team_region_bytes,
    } = parse_team_plan_groups(&mut reader)?;

    let marker_start = reader.position();
    let marker_value = read_ubjson_value(&mut reader)?;
    let marker_end = reader.position();
    let marker_region_bytes = reader.slice(marker_start, marker_end).to_vec();
    let markers = parse_markers_from_ubjson_value(&marker_value)?;
    let marker_count = markers.len();

    let custom_chunk_count = reader.read_u32()? as usize;
    let mut custom_region_bytes = Vec::new();
    custom_region_bytes.extend_from_slice(&(custom_chunk_count as u32).to_be_bytes());
    let mut custom_chunks = Vec::with_capacity(custom_chunk_count);
    let mut seen_custom_chunk_names = HashSet::with_capacity(custom_chunk_count);
    for _ in 0..custom_chunk_count {
        let name = reader.read_java_utf()?;
        if !seen_custom_chunk_names.insert(name.clone()) {
            return Err(format!("duplicate custom chunk name in world bundle: {name}"));
        }
        write_java_utf(&mut custom_region_bytes, &name)?;
        let chunk_len = reader.read_u32()? as usize;
        custom_region_bytes.extend_from_slice(&(chunk_len as u32).to_be_bytes());
        let chunk_bytes = reader.read_exact_vec(chunk_len)?;
        custom_region_bytes.extend_from_slice(&chunk_bytes);
        let parsed = parse_known_custom_chunk(&name, &chunk_bytes)?;
        custom_chunks.push(CustomChunkEntry {
            name,
            chunk_len,
            chunk_sha256: sha256_hex(&chunk_bytes),
            chunk_bytes,
            parsed,
        });
    }

    let mut tail = marker_region_bytes.clone();
    tail.extend_from_slice(&custom_region_bytes);

    let trailing = reader.remaining_bytes();
    if !trailing.is_empty() {
        return Err(format!(
            "unexpected trailing bytes after custom chunks in world bundle: {}",
            trailing.len()
        ));
    }

    let mut building_center_lookup = vec![None; tile_count];
    for (center_index, center) in building_centers.iter().enumerate() {
        building_center_lookup[center.tile_index] = Some(center_index);
    }

    let tiles = (0..tile_count)
        .map(|tile_index| TileModel {
            tile_index,
            x: tile_index % width,
            y: tile_index / width,
            floor_id: floors[tile_index],
            overlay_id: overlays[tile_index],
            block_id: blocks[tile_index],
            building_center_index: building_center_lookup[tile_index],
        })
        .collect();

    Ok(WorldBundle {
        compressed: compressed.to_vec(),
        inflated,
        rules_json,
        map_locales_json,
        tag_pairs,
        wave,
        wavetime_bits,
        tick_bits,
        rand0,
        rand1,
        player,
        content_header,
        patches,
        floor_runs,
        floor_region_bytes,
        block_runs,
        block_region_bytes,
        world: WorldModel {
            width,
            height,
            floors,
            overlays,
            blocks,
            tiles,
            building_centers,
            data_tiles,
            team_count,
            total_plans,
            team_ids,
            team_plan_counts,
        },
        team_plan_groups,
        team_region_bytes,
        marker_count,
        marker_region_bytes,
        markers,
        custom_chunks,
        custom_region_bytes,
        tail,
    })
}

pub fn format_world_model_goldens(model: &WorldModel) -> String {
    let mut lines = Vec::new();
    push_hex(&mut lines, "map.width", model.width as u32, 4);
    push_hex(&mut lines, "map.height", model.height as u32, 4);
    push_str(
        &mut lines,
        "floors.sha256",
        &sha256_hex(&shorts_to_bytes(&model.floors)),
    );
    push_str(
        &mut lines,
        "overlays.sha256",
        &sha256_hex(&shorts_to_bytes(&model.overlays)),
    );
    push_str(
        &mut lines,
        "blocks.sha256",
        &sha256_hex(&shorts_to_bytes(&model.blocks)),
    );
    push_hex(
        &mut lines,
        "buildingCenters.count",
        model.building_centers.len() as u32,
        8,
    );
    push_str(
        &mut lines,
        "buildingCenters.positions",
        &u32s_to_hex(
            &model
                .building_centers
                .iter()
                .map(|b| b.tile_index as u32)
                .collect::<Vec<_>>(),
        ),
    );
    push_str(
        &mut lines,
        "buildingCenters.xs",
        &u32s_to_hex(
            &model
                .building_centers
                .iter()
                .map(|b| b.x as u32)
                .collect::<Vec<_>>(),
        ),
    );
    push_str(
        &mut lines,
        "buildingCenters.ys",
        &u32s_to_hex(
            &model
                .building_centers
                .iter()
                .map(|b| b.y as u32)
                .collect::<Vec<_>>(),
        ),
    );
    push_str(
        &mut lines,
        "buildingCenters.blocks",
        &u32s_to_hex(
            &model
                .building_centers
                .iter()
                .map(|b| b.block_id as u32)
                .collect::<Vec<_>>(),
        ),
    );
    push_str(
        &mut lines,
        "buildingCenters.chunkLens",
        &u32s_to_hex(
            &model
                .building_centers
                .iter()
                .map(|b| b.chunk_len as u32)
                .collect::<Vec<_>>(),
        ),
    );
    push_str(
        &mut lines,
        "buildingCenters.chunkHashes",
        &model
            .building_centers
            .iter()
            .map(|b| b.chunk_sha256.clone())
            .collect::<Vec<_>>()
            .join(","),
    );
    for (index, center) in model.building_centers.iter().enumerate() {
        let prefix = format!("buildingCenters.{index}");
        push_hex(
            &mut lines,
            &format!("{prefix}.revision"),
            center.building.revision as u32,
            2,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.baseLen"),
            center.building.base_len as u32,
            8,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.tailLen"),
            center.building.tail_len as u32,
            8,
        );
        push_str(
            &mut lines,
            &format!("{prefix}.tailSha256"),
            &center.building.tail_sha256,
        );
        push_str(
            &mut lines,
            &format!("{prefix}.tail.kind"),
            match &center.building.parsed_tail {
                ParsedBuildingTail::Empty => "empty",
                ParsedBuildingTail::Conveyor(_) => "conveyor",
                ParsedBuildingTail::StackConveyor(_) => "stackConveyor",
                ParsedBuildingTail::Core(_) => "core",
                ParsedBuildingTail::UnitFactory(_) => "unitFactory",
                ParsedBuildingTail::Reconstructor(_) => "reconstructor",
                ParsedBuildingTail::NullableItemRef(_) => "nullableItemRef",
                ParsedBuildingTail::ItemBridge(_) => "itemBridge",
                ParsedBuildingTail::BufferedItemBridge(_) => "bufferedItemBridge",
                ParsedBuildingTail::MassDriver(_) => "massDriver",
                ParsedBuildingTail::Junction(_) => "junction",
                ParsedBuildingTail::SorterLegacy(_) => "sorterLegacy",
                ParsedBuildingTail::Turret(_) => "turret",
                ParsedBuildingTail::ItemTurret(_) => "itemTurret",
                ParsedBuildingTail::ContinuousTurret(_) => "continuousTurret",
                ParsedBuildingTail::BuildTurret(_) => "buildTurret",
                ParsedBuildingTail::PayloadLoader(_) => "payloadLoader",
                ParsedBuildingTail::PayloadSource(_) => "payloadSource",
                ParsedBuildingTail::PayloadRouter(_) => "payloadRouter",
                ParsedBuildingTail::PayloadMassDriver(_) => "payloadMassDriver",
                ParsedBuildingTail::BlockProducer(_) => "blockProducer",
                ParsedBuildingTail::Constructor(_) => "constructor",
                ParsedBuildingTail::UnitAssembler(_) => "unitAssembler",
                ParsedBuildingTail::OneF32(_) => "oneF32",
                ParsedBuildingTail::OneI8(_) => "oneI8",
                ParsedBuildingTail::OneI32(_) => "oneI32",
                ParsedBuildingTail::OneBool(_) => "oneBool",
                ParsedBuildingTail::OneF32Bool(_) => "oneF32Bool",
                ParsedBuildingTail::TwoF32(_) => "twoF32",
                ParsedBuildingTail::TwoF32I32(_) => "twoF32I32",
                ParsedBuildingTail::ThreeF32(_) => "threeF32",
                ParsedBuildingTail::FiveF32(_) => "fiveF32",
                ParsedBuildingTail::LandingPad(_) => "landingPad",
                ParsedBuildingTail::Message(_) => "message",
                ParsedBuildingTail::DuctUnloader(_) => "ductUnloader",
                ParsedBuildingTail::Memory(_) => "memory",
                ParsedBuildingTail::Canvas(_) => "canvas",
                ParsedBuildingTail::Unknown => "unknown",
            },
        );
        match &center.building.parsed_tail {
            ParsedBuildingTail::Conveyor(conveyor) => {
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.conveyor.len"),
                    conveyor.len as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.conveyor.itemIds"),
                    &u32s_to_hex(
                        &conveyor
                            .items
                            .iter()
                            .map(|item| item.item_id as u32)
                            .collect::<Vec<_>>(),
                    ),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.conveyor.xs"),
                    &i32s_to_hex(
                        &conveyor
                            .items
                            .iter()
                            .map(|item| item.x_raw as i32)
                            .collect::<Vec<_>>(),
                    ),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.conveyor.ys"),
                    &i32s_to_hex(
                        &conveyor
                            .items
                            .iter()
                            .map(|item| item.y_raw as i32)
                            .collect::<Vec<_>>(),
                    ),
                );
            }
            ParsedBuildingTail::StackConveyor(stack_conveyor) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.stackConveyor.link"),
                    &format!("{:08x}", stack_conveyor.link as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.stackConveyor.cooldownBits"),
                    &format!("{:08x}", stack_conveyor.cooldown_bits),
                );
            }
            ParsedBuildingTail::Core(core) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.core.commandPosPresent"),
                    if core.command_pos_present { "1" } else { "0" },
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.core.commandPosXBits"),
                    &format!("{:08x}", core.command_pos_x_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.core.commandPosYBits"),
                    &format!("{:08x}", core.command_pos_y_bits),
                );
            }
            ParsedBuildingTail::ItemBridge(bridge) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemBridge.link"),
                    &format!("{:08x}", bridge.link as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemBridge.warmupBits"),
                    &format!("{:08x}", bridge.warmup_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemBridge.incoming"),
                    &i32s_to_hex(&bridge.incoming),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemBridge.moved"),
                    if bridge.moved { "1" } else { "0" },
                );
            }
            ParsedBuildingTail::BufferedItemBridge(buffered) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.link"),
                    &format!("{:08x}", buffered.bridge.link as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.warmupBits"),
                    &format!("{:08x}", buffered.bridge.warmup_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.incoming"),
                    &i32s_to_hex(&buffered.bridge.incoming),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.moved"),
                    if buffered.bridge.moved { "1" } else { "0" },
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.bufferIndex"),
                    &format!("{:02x}", buffered.buffer.index as u8),
                );
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.bufferCapacity"),
                    buffered.buffer.capacity as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.bufferNormalizedIndex"),
                    &format!("{:08x}", buffered.buffer.normalized_index as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.bufferItemIds"),
                    &i32s_to_hex(
                        &buffered
                            .buffer
                            .entries
                            .iter()
                            .map(|entry| entry.item_id as i32)
                            .collect::<Vec<_>>(),
                    ),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.bufferData"),
                    &i32s_to_hex(
                        &buffered
                            .buffer
                            .entries
                            .iter()
                            .map(|entry| entry.data as i32)
                            .collect::<Vec<_>>(),
                    ),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.bufferedItemBridge.bufferTimeBits"),
                    &u32s_to_hex(
                        &buffered
                            .buffer
                            .entries
                            .iter()
                            .map(|entry| entry.time_bits)
                            .collect::<Vec<_>>(),
                    ),
                );
            }
            ParsedBuildingTail::MassDriver(driver) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.massDriver.link"),
                    &format!("{:08x}", driver.link as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.massDriver.rotationBits"),
                    &format!("{:08x}", driver.rotation_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.massDriver.state"),
                    &format!("{:02x}", driver.state_ordinal),
                );
            }
            ParsedBuildingTail::Junction(junction) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.junction.legacy"),
                    if junction.buffer.legacy { "1" } else { "0" },
                );
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.junction.sideCount"),
                    junction.buffer.sides.len() as u32,
                    8,
                );
                for (side_index, side) in junction.buffer.sides.iter().enumerate() {
                    let side_prefix = format!("{prefix}.tail.junction.side{side_index}");
                    push_str(
                        &mut lines,
                        &format!("{side_prefix}.index"),
                        &format!("{:02x}", side.index as u8),
                    );
                    push_hex(
                        &mut lines,
                        &format!("{side_prefix}.capacity"),
                        side.capacity as u32,
                        8,
                    );
                    push_str(
                        &mut lines,
                        &format!("{side_prefix}.itemIds"),
                        &i32s_to_hex(
                            &side
                                .entries
                                .iter()
                                .map(|entry| entry.item_id as i32)
                                .collect::<Vec<_>>(),
                        ),
                    );
                    push_str(
                        &mut lines,
                        &format!("{side_prefix}.timeBits"),
                        &u32s_to_hex(
                            &side
                                .entries
                                .iter()
                                .map(|entry| entry.time_bits)
                                .collect::<Vec<_>>(),
                        ),
                    );
                }
            }
            ParsedBuildingTail::SorterLegacy(sorter) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.sorterLegacy.itemRef"),
                    &sorter
                        .item_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.sorterLegacy.buffer.legacy"),
                    if sorter.buffer.legacy { "1" } else { "0" },
                );
                for (side_index, side) in sorter.buffer.sides.iter().enumerate() {
                    let side_prefix = format!("{prefix}.tail.sorterLegacy.buffer.side{side_index}");
                    push_str(
                        &mut lines,
                        &format!("{side_prefix}.index"),
                        &format!("{:02x}", side.index as u8),
                    );
                    push_hex(
                        &mut lines,
                        &format!("{side_prefix}.capacity"),
                        side.capacity as u32,
                        8,
                    );
                    push_str(
                        &mut lines,
                        &format!("{side_prefix}.itemIds"),
                        &i32s_to_hex(
                            &side
                                .entries
                                .iter()
                                .map(|entry| entry.item_id as i32)
                                .collect::<Vec<_>>(),
                        ),
                    );
                    push_str(
                        &mut lines,
                        &format!("{side_prefix}.timeBits"),
                        &u32s_to_hex(
                            &side
                                .entries
                                .iter()
                                .map(|entry| entry.time_bits)
                                .collect::<Vec<_>>(),
                        ),
                    );
                }
            }
            ParsedBuildingTail::Turret(turret) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.turret.reloadCounterBits"),
                    &format!("{:08x}", turret.reload_counter_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.turret.rotationBits"),
                    &format!("{:08x}", turret.rotation_bits),
                );
            }
            ParsedBuildingTail::ItemTurret(turret) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemTurret.reloadCounterBits"),
                    &format!("{:08x}", turret.turret.reload_counter_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemTurret.rotationBits"),
                    &format!("{:08x}", turret.turret.rotation_bits),
                );
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.itemTurret.ammoCount"),
                    turret.ammo_count as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemTurret.itemIds"),
                    &u32s_to_hex(
                        &turret
                            .ammo
                            .iter()
                            .map(|entry| entry.item_id as u32)
                            .collect::<Vec<_>>(),
                    ),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemTurret.amounts"),
                    &i32s_to_hex(
                        &turret
                            .ammo
                            .iter()
                            .map(|entry| entry.amount as i32)
                            .collect::<Vec<_>>(),
                    ),
                );
            }
            ParsedBuildingTail::ContinuousTurret(turret) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.continuousTurret.reloadCounterBits"),
                    &format!("{:08x}", turret.turret.reload_counter_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.continuousTurret.rotationBits"),
                    &format!("{:08x}", turret.turret.rotation_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.continuousTurret.lastLengthBits"),
                    &format!("{:08x}", turret.last_length_bits),
                );
            }
            ParsedBuildingTail::BuildTurret(turret) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.buildTurret.rotationBits"),
                    &format!("{:08x}", turret.rotation_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.buildTurret.plansPresent"),
                    if turret.plans_present { "1" } else { "0" },
                );
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.buildTurret.planCount"),
                    turret.plan_count as u32,
                    8,
                );
                for (plan_index, plan) in turret.plans.iter().enumerate() {
                    let plan_prefix = format!("{prefix}.tail.buildTurret.plan{plan_index}");
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.breaking"),
                        if plan.breaking { "1" } else { "0" },
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.packedPosition"),
                        &format!("{:08x}", plan.packed_position as u32),
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.x"),
                        &format!("{:08x}", plan.x as u32),
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.y"),
                        &format!("{:08x}", plan.y as u32),
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.blockId"),
                        &plan
                            .block_id
                            .map(|value| format!("{:04x}", value))
                            .unwrap_or_else(|| "none".to_string()),
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.rotation"),
                        &plan
                            .rotation
                            .map(|value| format!("{:02x}", value))
                            .unwrap_or_else(|| "none".to_string()),
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.hasConfig"),
                        if plan.has_config { "1" } else { "0" },
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.configKind"),
                        &plan.config_kind,
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.configValue"),
                        &plan.config_value,
                    );
                    push_str(
                        &mut lines,
                        &format!("{plan_prefix}.configSha256"),
                        &plan.config_sha256,
                    );
                    push_hex(
                        &mut lines,
                        &format!("{plan_prefix}.configLength"),
                        plan.config_bytes.len() as u32,
                        8,
                    );
                }
            }
            ParsedBuildingTail::UnitFactory(factory) => {
                push_world_model_payload_block_lines(&mut lines, &prefix, &factory.payload_block);
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitFactory.progressBits"),
                    &format!("{:08x}", factory.progress_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitFactory.currentPlan"),
                    &format!("{:04x}", factory.current_plan as u16),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitFactory.commandPosPresent"),
                    if factory.command_pos.present {
                        "1"
                    } else {
                        "0"
                    },
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitFactory.commandPosXBits"),
                    &format!("{:08x}", factory.command_pos.x_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitFactory.commandPosYBits"),
                    &format!("{:08x}", factory.command_pos.y_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitFactory.command"),
                    &factory
                        .command_id
                        .map(|value| format!("{:02x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
            }
            ParsedBuildingTail::Reconstructor(reconstructor) => {
                push_world_model_payload_block_lines(
                    &mut lines,
                    &prefix,
                    &reconstructor.payload_block,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.reconstructor.progressBits"),
                    &format!("{:08x}", reconstructor.progress_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.reconstructor.commandPosPresent"),
                    if reconstructor.command_pos.present {
                        "1"
                    } else {
                        "0"
                    },
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.reconstructor.commandPosXBits"),
                    &format!("{:08x}", reconstructor.command_pos.x_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.reconstructor.commandPosYBits"),
                    &format!("{:08x}", reconstructor.command_pos.y_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.reconstructor.command"),
                    &reconstructor
                        .command_id
                        .map(|value| format!("{:02x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
            }
            ParsedBuildingTail::PayloadLoader(loader) => {
                push_world_model_payload_block_lines(&mut lines, &prefix, &loader.payload_block);
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadLoader.exporting"),
                    if loader.exporting { "1" } else { "0" },
                );
            }
            ParsedBuildingTail::PayloadSource(source) => {
                push_world_model_payload_block_lines(&mut lines, &prefix, &source.payload_block);
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadSource.unitId"),
                    &source
                        .unit_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadSource.configBlockId"),
                    &source
                        .config_block_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadSource.commandPosPresent"),
                    if source.command_pos.present { "1" } else { "0" },
                );
            }
            ParsedBuildingTail::PayloadRouter(router) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.progressBits"),
                    &format!("{:08x}", router.progress_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.itemRotationBits"),
                    &format!("{:08x}", router.item_rotation_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.payloadPresent"),
                    if router.payload_present { "1" } else { "0" },
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.payloadType"),
                    &format_optional_byte(router.payload_type),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.payloadKind"),
                    payload_snapshot_kind(router.parsed_payload.as_deref(), router.payload_present),
                );
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.payloadSerializedLen"),
                    router.payload_serialized_len as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.payloadSerializedSha256"),
                    &router.payload_serialized_sha256,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.sorted"),
                    &format_mixed_content_ref(&router.sorted),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.sortedContentType"),
                    &format_optional_byte(router.sorted.content_type),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.sortedContentId"),
                    &format_optional_item_id(router.sorted.content_id),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadRouter.recDir"),
                    &format!("{:02x}", router.rec_dir),
                );
                match router.parsed_payload.as_deref() {
                    Some(PayloadSnapshot::Build(build)) => {
                        let payload_build_block_id = if build.block_id >= 0 {
                            format!("{:04x}", build.block_id as u16)
                        } else {
                            "none".to_string()
                        };
                        push_str(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadBuildBlockId"),
                            &payload_build_block_id,
                        );
                        push_str(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadBuildRevision"),
                            &format!("{:02x}", build.build_revision),
                        );
                        push_str(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadBuildTailKind"),
                            building_tail_kind(&build.building_sync.parsed_tail),
                        );
                    }
                    Some(PayloadSnapshot::Unit(unit)) => {
                        push_str(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadUnitClassId"),
                            &format!("{:02x}", unit.class_id),
                        );
                        push_str(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadUnitRevision"),
                            &format!("{:04x}", unit.revision as u16),
                        );
                        push_hex(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadUnitBodyLen"),
                            unit.body_len as u32,
                            8,
                        );
                        push_str(
                            &mut lines,
                            &format!("{prefix}.tail.payloadRouter.payloadUnitBodySha256"),
                            &unit.body_sha256,
                        );
                    }
                    Some(PayloadSnapshot::Null) | None => {}
                }
            }
            ParsedBuildingTail::PayloadMassDriver(driver) => {
                push_world_model_payload_block_lines(&mut lines, &prefix, &driver.payload_block);
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadMassDriver.link"),
                    &format!("{:08x}", driver.link as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadMassDriver.turretRotationBits"),
                    &format!("{:08x}", driver.turret_rotation_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.payloadMassDriver.state"),
                    &format!("{:02x}", driver.state_ordinal),
                );
            }
            ParsedBuildingTail::BlockProducer(producer) => {
                push_world_model_payload_block_lines(&mut lines, &prefix, &producer.payload_block);
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.blockProducer.progressBits"),
                    &format!("{:08x}", producer.progress_bits),
                );
            }
            ParsedBuildingTail::Constructor(constructor) => {
                push_world_model_payload_block_lines(
                    &mut lines,
                    &prefix,
                    &constructor.payload_block,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.constructor.progressBits"),
                    &format!("{:08x}", constructor.progress_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.constructor.recipeBlockId"),
                    &constructor
                        .recipe_block_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "ffff".to_string()),
                );
            }
            ParsedBuildingTail::UnitAssembler(assembler) => {
                push_world_model_payload_block_lines(&mut lines, &prefix, &assembler.payload_block);
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitAssembler.progressBits"),
                    &format!("{:08x}", assembler.progress_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitAssembler.unitIds"),
                    &i32s_to_hex(&assembler.unit_ids),
                );
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.unitAssembler.blockCount"),
                    assembler.blocks.entry_count as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.unitAssembler.commandPosPresent"),
                    if assembler.command_pos.present {
                        "1"
                    } else {
                        "0"
                    },
                );
            }
            ParsedBuildingTail::OneF32(value) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.oneF32.bits"),
                    &format!("{:08x}", value.bits),
                );
            }
            ParsedBuildingTail::OneI8(value) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.oneI8.value"),
                    &format!("{:02x}", value.value as u8),
                );
            }
            ParsedBuildingTail::OneI32(value) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.oneI32.value"),
                    &format!("{:08x}", value.value as u32),
                );
            }
            ParsedBuildingTail::OneBool(value) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.oneBool.value"),
                    if value.value { "1" } else { "0" },
                );
            }
            ParsedBuildingTail::OneF32Bool(value) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.oneF32Bool.bits"),
                    &format!("{:08x}", value.bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.oneF32Bool.flag"),
                    if value.flag { "1" } else { "0" },
                );
            }
            ParsedBuildingTail::TwoF32(values) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.twoF32.firstBits"),
                    &format!("{:08x}", values.first_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.twoF32.secondBits"),
                    &format!("{:08x}", values.second_bits),
                );
            }
            ParsedBuildingTail::TwoF32I32(values) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.twoF32I32.firstBits"),
                    &format!("{:08x}", values.first_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.twoF32I32.secondBits"),
                    &format!("{:08x}", values.second_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.twoF32I32.thirdValue"),
                    &format!("{:08x}", values.third_value as u32),
                );
            }
            ParsedBuildingTail::ThreeF32(values) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.threeF32.firstBits"),
                    &format!("{:08x}", values.first_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.threeF32.secondBits"),
                    &format!("{:08x}", values.second_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.threeF32.thirdBits"),
                    &format!("{:08x}", values.third_bits),
                );
            }
            ParsedBuildingTail::FiveF32(values) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.fiveF32.firstBits"),
                    &format!("{:08x}", values.first_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.fiveF32.secondBits"),
                    &format!("{:08x}", values.second_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.fiveF32.thirdBits"),
                    &format!("{:08x}", values.third_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.fiveF32.fourthBits"),
                    &format!("{:08x}", values.fourth_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.fiveF32.fifthBits"),
                    &format!("{:08x}", values.fifth_bits),
                );
            }
            ParsedBuildingTail::LandingPad(landing_pad) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.landingPad.config"),
                    &landing_pad
                        .config_item_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.landingPad.priority"),
                    &format!("{:08x}", landing_pad.priority as u32),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.landingPad.cooldown"),
                    &format!("{:08x}", landing_pad.cooldown_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.landingPad.arriving"),
                    &landing_pad
                        .arriving_item_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.landingPad.arrivingTimer"),
                    &format!("{:08x}", landing_pad.arriving_timer_bits),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.landingPad.liquidRemoved"),
                    &format!("{:08x}", landing_pad.liquid_removed_bits),
                );
            }
            ParsedBuildingTail::Message(message) => {
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.message.byteLength"),
                    message.message.len() as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.message.sha256"),
                    &sha256_hex(message.message.as_bytes()),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.message.textEscaped"),
                    &message.message.escape_default().to_string(),
                );
            }
            ParsedBuildingTail::DuctUnloader(duct_unloader) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.ductUnloader.itemRef"),
                    &format_optional_item_id(duct_unloader.item_id),
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.ductUnloader.offset"),
                    &format!("{:04x}", duct_unloader.offset as u16),
                );
            }
            ParsedBuildingTail::Memory(memory) => {
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.memory.len"),
                    memory.len as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.memory.valuesSha256"),
                    &sha256_hex(&u64s_to_bytes(&memory.values_bits)),
                );
            }
            ParsedBuildingTail::Canvas(canvas) => {
                push_hex(
                    &mut lines,
                    &format!("{prefix}.tail.canvas.dataLen"),
                    canvas.data_len as u32,
                    8,
                );
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.canvas.dataSha256"),
                    &canvas.data_sha256,
                );
            }
            ParsedBuildingTail::NullableItemRef(item_ref) => {
                push_str(
                    &mut lines,
                    &format!("{prefix}.tail.itemRef"),
                    &item_ref
                        .item_id
                        .map(|value| format!("{:04x}", value))
                        .unwrap_or_else(|| "none".to_string()),
                );
            }
            ParsedBuildingTail::Empty | ParsedBuildingTail::Unknown => {}
        }
        push_str(
            &mut lines,
            &format!("{prefix}.base.legacy"),
            if center.building.base.legacy {
                "1"
            } else {
                "0"
            },
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.healthBits"),
            &format!("{:08x}", center.building.base.health_bits),
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.base.rotation"),
            center.building.base.rotation as u32,
            2,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.base.team"),
            center.building.base.team_id as u32,
            2,
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.saveVersion"),
            &center
                .building
                .base
                .save_version
                .map(|value| format!("{:02x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.enabled"),
            match center.building.base.enabled {
                Some(true) => "1",
                Some(false) => "0",
                None => "none",
            },
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.moduleBitmask"),
            &center
                .building
                .base
                .module_bitmask
                .map(|value| format!("{:02x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.base.itemEntries"),
            center
                .building
                .base
                .item_module
                .as_ref()
                .map(|module| module.count as u32)
                .unwrap_or(0),
            8,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.base.powerLinks"),
            center
                .building
                .base
                .power_module
                .as_ref()
                .map(|module| module.link_count as u32)
                .unwrap_or(0),
            8,
        );
        push_hex(
            &mut lines,
            &format!("{prefix}.base.liquidEntries"),
            center
                .building
                .base
                .liquid_module
                .as_ref()
                .map(|module| module.count as u32)
                .unwrap_or(0),
            8,
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.timeScaleBits"),
            &center
                .building
                .base
                .time_scale_bits
                .map(|value| format!("{:08x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.timeScaleDurationBits"),
            &center
                .building
                .base
                .time_scale_duration_bits
                .map(|value| format!("{:08x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.lastDisablerPos"),
            &center
                .building
                .base
                .last_disabler_pos
                .map(|value| format!("{:08x}", value as u32))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.legacyConsumeConnected"),
            match center.building.base.legacy_consume_connected {
                Some(true) => "1",
                Some(false) => "0",
                None => "none",
            },
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.efficiency"),
            &center
                .building
                .base
                .efficiency
                .map(|value| format!("{:02x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.optionalEfficiency"),
            &center
                .building
                .base
                .optional_efficiency
                .map(|value| format!("{:02x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
        push_str(
            &mut lines,
            &format!("{prefix}.base.visibleFlags"),
            &center
                .building
                .base
                .visible_flags
                .map(|value| format!("{:016x}", value))
                .unwrap_or_else(|| "none".to_string()),
        );
    }
    push_hex(&mut lines, "dataTiles", model.data_tiles as u32, 8);
    push_hex(
        &mut lines,
        "teamBlocks.teamCount",
        model.team_count as u32,
        8,
    );
    push_hex(
        &mut lines,
        "teamBlocks.totalPlans",
        model.total_plans as u32,
        8,
    );
    push_str(
        &mut lines,
        "teamBlocks.teamIds",
        &u32s_to_hex(&model.team_ids),
    );
    push_str(
        &mut lines,
        "teamBlocks.planCounts",
        &u32s_to_hex(&model.team_plan_counts),
    );
    lines
        .into_iter()
        .map(|(k, v)| format!("{k}={v}"))
        .collect::<Vec<_>>()
        .join("\n")
}

pub fn format_world_load_goldens(summary: &WorldLoadSummary) -> String {
    summary
        .lines
        .iter()
        .map(|(k, v)| format!("{k}={v}"))
        .collect::<Vec<_>>()
        .join("\n")
}

