fn push_world_enter_playable_session_entry_loop_summary_lines(
    lines: &mut Vec<(String, String)>,
    prefix: &str,
    entry_loop_summary: &WorldEnterPlayableSessionEntryLoopSummaryContract,
) {
    let entry_control_summary = entry_loop_summary_as_entry_control_summary(entry_loop_summary);
    push_world_enter_playable_session_entry_control_summary_lines(
        lines,
        prefix,
        &entry_control_summary,
    );
    push_str(
        lines,
        &format!("{prefix}.interactionReady"),
        if entry_loop_summary.interaction_ready {
            "1"
        } else {
            "0"
        },
    );
    push_str(
        lines,
        &format!("{prefix}.clientLoaded"),
        if entry_loop_summary.client_loaded {
            "1"
        } else {
            "0"
        },
    );
    push_str(
        lines,
        &format!("{prefix}.hasConnected"),
        if entry_loop_summary.has_connected {
            "1"
        } else {
            "0"
        },
    );
}

