fn push_world_enter_playable_session_entry_proof_summary_lines(
    lines: &mut Vec<(String, String)>,
    prefix: &str,
    entry_proof_summary: &WorldEnterPlayableSessionEntryProofSummaryContract,
) {
    let entry_lifecycle_summary =
        entry_proof_summary_as_entry_lifecycle_summary(entry_proof_summary);
    push_world_enter_playable_session_entry_lifecycle_summary_lines(
        lines,
        prefix,
        &entry_lifecycle_summary,
    );
    push_hex(
        lines,
        &format!("{prefix}.blockerCount"),
        entry_proof_summary.blocker_count as u32,
        8,
    );
    push_str(
        lines,
        &format!("{prefix}.blockers"),
        if entry_proof_summary.blockers.is_empty() {
            "none".to_string()
        } else {
            entry_proof_summary.blockers.join(",")
        }
        .as_str(),
    );
    push_str(
        lines,
        &format!("{prefix}.playerNameSha256"),
        &entry_proof_summary.player_name_sha256,
    );
    push_hex(
        lines,
        &format!("{prefix}.playerUnitType"),
        entry_proof_summary.player_unit_type as u32,
        2,
    );
    push_hex(
        lines,
        &format!("{prefix}.playerXBits"),
        entry_proof_summary.player_x_bits,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.playerYBits"),
        entry_proof_summary.player_y_bits,
        8,
    );
}

