fn push_world_enter_playable_session_entry_world_summary_lines(
    lines: &mut Vec<(String, String)>,
    prefix: &str,
    entry_world_summary: &WorldEnterPlayableSessionEntryWorldSummaryContract,
) {
    let entry_proof_summary = entry_world_summary_as_entry_proof_summary(entry_world_summary);
    push_world_enter_playable_session_entry_proof_summary_lines(
        lines,
        prefix,
        &entry_proof_summary,
    );
    push_hex(
        lines,
        &format!("{prefix}.wavetimeBits"),
        entry_world_summary.wavetime_bits,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.teamCount"),
        entry_world_summary.team_count as u32,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.customChunkCount"),
        entry_world_summary.custom_chunk_count as u32,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.floorRuns"),
        entry_world_summary.floor_runs as u32,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.blockRuns"),
        entry_world_summary.block_runs as u32,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.buildingCenters"),
        entry_world_summary.building_centers as u32,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.dataTiles"),
        entry_world_summary.data_tiles as u32,
        8,
    );
    push_hex(
        lines,
        &format!("{prefix}.staticFogWidth"),
        entry_world_summary.static_fog_width as u32,
        4,
    );
    push_hex(
        lines,
        &format!("{prefix}.staticFogHeight"),
        entry_world_summary.static_fog_height as u32,
        4,
    );
    push_str(
        lines,
        &format!("{prefix}.teamIds"),
        &u32s_to_hex(&entry_world_summary.team_ids),
    );
    push_str(
        lines,
        &format!("{prefix}.fogTeamIds"),
        &u32s_to_hex(&entry_world_summary.fog_team_ids),
    );
    push_str(
        lines,
        &format!("{prefix}.markerIds"),
        &u32s_to_hex(&entry_world_summary.marker_ids),
    );
    push_str(
        lines,
        &format!("{prefix}.markerClassTags"),
        &entry_world_summary.marker_class_tags.join(","),
    );
    push_str(
        lines,
        &format!("{prefix}.markerColors"),
        &entry_world_summary.marker_colors.join(","),
    );
    push_str(
        lines,
        &format!("{prefix}.planConfigKinds"),
        &entry_world_summary.plan_config_kinds.join(","),
    );
    push_str(
        lines,
        &format!("{prefix}.planConfigHashes"),
        &entry_world_summary.plan_config_hashes.join(","),
    );
    push_str(
        lines,
        &format!("{prefix}.staticFogRevealedCounts"),
        &u32s_to_hex(&entry_world_summary.static_fog_revealed_counts),
    );
}

