fn sync_state_core_team_ids_to_string(teams: &[WorldEnterSyncStateCoreTeamContract]) -> String {
    teams
        .iter()
        .map(|team| format!("{:02x}", team.team_id))
        .collect::<Vec<_>>()
        .join(",")
}

fn sync_state_core_items_to_string(teams: &[WorldEnterSyncStateCoreTeamContract]) -> String {
    teams
        .iter()
        .flat_map(|team| team.items.iter())
        .map(|item| format!("{:04x}:{:08x}", item.item_id, item.amount))
        .collect::<Vec<_>>()
        .join(",")
}

