    fn sample_msav_bytes(
        save_version: i32,
        leading_region_length: Option<u32>,
        body_tail: &[u8],
    ) -> Vec<u8> {
        let mut inflated = Vec::new();
        inflated.extend_from_slice(&MSAV_HEADER);
        inflated.extend_from_slice(&save_version.to_be_bytes());
        if let Some(length) = leading_region_length {
            inflated.extend_from_slice(&length.to_be_bytes());
        }
        inflated.extend_from_slice(body_tail);
        mdt_protocol::deflate_zlib(&inflated).unwrap()
    }

    #[test]
    fn rejects_truncated_java_modified_utf_two_byte_sequence() {
        let error = decode_java_modified_utf(&[0xc2]).unwrap_err();

        assert!(error.contains("truncated Java modified UTF-8 two-byte sequence"));
    }

    #[test]
    fn rejects_invalid_java_modified_utf_continuation_byte() {
        let error = decode_java_modified_utf(&[0xc2, 0x20]).unwrap_err();

        assert!(error.contains("invalid Java modified UTF-8 continuation byte"));
    }

    #[test]
    fn rejects_truncated_java_modified_utf_three_byte_sequence() {
        let error = decode_java_modified_utf(&[0xe1, 0x80]).unwrap_err();

        assert!(error.contains("truncated Java modified UTF-8 three-byte sequence"));
    }

    #[test]
    fn rejects_invalid_java_modified_utf_three_byte_continuation_bytes() {
        let error = decode_java_modified_utf(&[0xe1, 0x80, 0x20]).unwrap_err();

        assert!(error.contains("invalid Java modified UTF-8 continuation bytes"));
    }

    #[test]
    fn rejects_unsupported_java_modified_utf_leading_byte() {
        let error = decode_java_modified_utf(&[0x80]).unwrap_err();

        assert!(error.contains("unsupported Java modified UTF-8 leading byte"));
    }

    #[test]
    fn rejects_truncated_msav_zlib_header() {
        let error = read_msav_zlib_header(&[0x78]).unwrap_err();

        assert!(error.contains(".msav envelope too short for zlib header"));
    }

    #[test]
    fn rejects_invalid_msav_zlib_header_checksum() {
        let error = read_msav_zlib_header(&[0x78, 0x00]).unwrap_err();

        assert!(error.contains("invalid .msav zlib header checksum"));
    }

    #[test]
    fn rejects_unsupported_msav_zlib_compression_method() {
        let error = read_msav_zlib_header(&[0x79, 0x01]).unwrap_err();

        assert!(error.contains("unsupported .msav zlib compression method"));
    }

    #[test]
    fn reads_msav_zlib_header_preserves_preset_dictionary_flag() {
        let header = read_msav_zlib_header(&[0x78, 0xbb]).unwrap();

        assert_eq!(header.cmf, 0x78);
        assert_eq!(header.flg, 0xbb);
        assert!(header.header_checksum_ok);
        assert!(header.preset_dictionary);
    }

    #[test]
    fn rejects_oversized_msav_inflate() {
        let inflated = vec![0u8; MAX_MSAV_INFLATED_BYTES + 1];
        let compressed = compress_zlib_bytes(&inflated);

        let error = inflate_zlib(&compressed).unwrap_err();
        assert!(error.contains("inflated .msav payload too large"));
    }

    fn encode_save_region(bytes: &[u8]) -> Vec<u8> {
        let mut out = Vec::new();
        out.extend_from_slice(&(bytes.len() as u32).to_be_bytes());
        out.extend_from_slice(bytes);
        out
    }

    fn encode_save_entity_chunk(
        save_version: i32,
        class_id: u8,
        entity_id: i32,
        body: &[u8],
    ) -> Vec<u8> {
        let mut chunk = Vec::new();
        chunk.push(class_id);
        chunk.extend_from_slice(&entity_id.to_be_bytes());
        chunk.extend_from_slice(body);

        let mut out = Vec::new();
        if save_version >= 10 {
            out.extend_from_slice(&(chunk.len() as u32).to_be_bytes());
        } else {
            out.extend_from_slice(&(chunk.len() as u16).to_be_bytes());
        }
        out.extend_from_slice(&chunk);
        out
    }

    fn encode_legacy_short_chunk(body: &[u8]) -> Vec<u8> {
        let mut out = Vec::new();
        out.extend_from_slice(&(body.len() as u16).to_be_bytes());
        out.extend_from_slice(body);
        out
    }

    fn encode_save_entity_chunk_without_id(class_id: u8, body: &[u8]) -> Vec<u8> {
        let mut chunk = Vec::new();
        chunk.push(class_id);
        chunk.extend_from_slice(body);
        encode_legacy_short_chunk(&chunk)
    }

    fn sample_legacy_save_entity_group_bytes() -> Vec<u8> {
        let mut out = Vec::new();
        out.push(1);
        out.extend_from_slice(&2u32.to_be_bytes());
        out.extend_from_slice(&encode_legacy_short_chunk(&[0xaa, 0xbb]));
        out.extend_from_slice(&encode_legacy_short_chunk(&[0xcc]));
        out
    }

    fn sample_save_entity_region_bytes(save_version: i32) -> Vec<u8> {
        let mut out = Vec::new();
        match save_version {
            1 | 2 => out.extend_from_slice(&sample_legacy_save_entity_group_bytes()),
            3 => {
                out.extend_from_slice(&generate_legacy_team_plan_sample_bytes());
                out.extend_from_slice(&sample_legacy_save_entity_group_bytes());
            }
            4 => {
                out.extend_from_slice(&generate_team_plan_sample_bytes());
                out.extend_from_slice(&2u32.to_be_bytes());
                out.extend_from_slice(&encode_save_entity_chunk(
                    save_version,
                    3,
                    0x0102_0304,
                    &[0xaa, 0xbb],
                ));
                out.extend_from_slice(&encode_save_entity_chunk(
                    save_version,
                    7,
                    0x1122_3344,
                    &[0xcc],
                ));
            }
            5 => {
                out.extend_from_slice(&1u16.to_be_bytes());
                out.extend_from_slice(&3u16.to_be_bytes());
                write_java_utf(&mut out, "mod-unit").unwrap();
                out.extend_from_slice(&generate_team_plan_sample_bytes());
                out.extend_from_slice(&2u32.to_be_bytes());
                out.extend_from_slice(&encode_save_entity_chunk_without_id(3, &[0xaa, 0xbb]));
                out.extend_from_slice(&encode_save_entity_chunk_without_id(7, &[0xcc]));
            }
            _ => {
                out.extend_from_slice(&1u16.to_be_bytes());
                out.extend_from_slice(&3u16.to_be_bytes());
                write_java_utf(&mut out, "mod-unit").unwrap();
                out.extend_from_slice(&generate_team_plan_sample_bytes());
                out.extend_from_slice(&2u32.to_be_bytes());
                out.extend_from_slice(&encode_save_entity_chunk(
                    save_version,
                    3,
                    0x0102_0304,
                    &[0xaa, 0xbb],
                ));
                out.extend_from_slice(&encode_save_entity_chunk(
                    save_version,
                    7,
                    0x1122_3344,
                    &[0xcc],
                ));
            }
        }
        out
    }

    fn sample_msav_save_bytes(save_version: i32) -> Vec<u8> {
        let entity_region = sample_save_entity_region_bytes(save_version);
        let mut inflated = Vec::new();
        inflated.extend_from_slice(&MSAV_HEADER);
        inflated.extend_from_slice(&save_version.to_be_bytes());

        for region_name in msav_region_names(save_version).unwrap() {
            let region_bytes = match *region_name {
                "meta" => vec![0xde, 0xad],
                "content" => vec![0xbe, 0xef],
                "patches" => vec![0x11],
                "map" => vec![0xfa, 0xce],
                "entities" => entity_region.clone(),
                "markers" => vec![0x33],
                "custom" => vec![0x44, 0x55],
                _ => unreachable!("unexpected region name: {region_name}"),
            };
            inflated.extend_from_slice(&encode_save_region(&region_bytes));
        }

        mdt_protocol::deflate_zlib(&inflated).unwrap()
    }

    fn encode_content_header_region(entries: &[ContentHeaderEntry]) -> Vec<u8> {
        let mut out = vec![entries.len() as u8];
        out.extend_from_slice(&serialize_content_header(entries).unwrap());
        out
    }

    fn encode_patch_region(patches: &[Vec<u8>]) -> Vec<u8> {
        let mut out = vec![patches.len() as u8];
        for patch in patches {
            out.extend_from_slice(&(patch.len() as u32).to_be_bytes());
            out.extend_from_slice(patch);
        }
        out
    }

    fn encode_save_map_region_from_bundle(bundle: &WorldBundle) -> Vec<u8> {
        let mut out = Vec::new();
        out.extend_from_slice(&(bundle.world.width as u16).to_be_bytes());
        out.extend_from_slice(&(bundle.world.height as u16).to_be_bytes());
        out.extend_from_slice(&bundle.floor_region_bytes);
        out.extend_from_slice(&bundle.block_region_bytes);
        out
    }

    fn encode_legacy_save_map_region_from_bundle(bundle: &WorldBundle) -> Vec<u8> {
        let mut out = Vec::new();
        out.extend_from_slice(&(bundle.world.width as u16).to_be_bytes());
        out.extend_from_slice(&(bundle.world.height as u16).to_be_bytes());
        out.extend_from_slice(&bundle.floor_region_bytes);

        let tile_count = bundle.world.width * bundle.world.height;
        let mut reader = Reader::new(&bundle.block_region_bytes);
        let mut i = 0usize;
        while i < tile_count {
            let block = reader.read_u16().unwrap();
            let packed = reader.read_u8().unwrap();
            let had_entity = (packed & 1) != 0;
            let had_data_old = (packed & 2) != 0;
            let had_data_new = (packed & 4) != 0;
            let mut is_center = true;

            out.extend_from_slice(&block.to_be_bytes());
            out.push(packed);

            if had_data_new {
                let data = reader.read_u8().unwrap();
                let floor_data = reader.read_u8().unwrap();
                let overlay_data = reader.read_u8().unwrap();
                let extra_data = reader.read_u32().unwrap();
                out.push(data);
                out.push(floor_data);
                out.push(overlay_data);
                out.extend_from_slice(&extra_data.to_be_bytes());
            }

            if had_entity {
                is_center = reader.read_bool().unwrap();
                out.push(u8::from(is_center));
            }

            if had_entity && is_center {
                let chunk_len = reader.read_u32().unwrap() as usize;
                let chunk = reader.read_exact_vec(chunk_len).unwrap();
                out.extend_from_slice(&(chunk_len as u16).to_be_bytes());
                out.extend_from_slice(&chunk);
            } else if had_data_old && !had_entity {
                out.push(reader.read_u8().unwrap());
            } else if !had_data_new && !had_entity {
                let consecutives = reader.read_u8().unwrap();
                out.push(consecutives);
                i += consecutives as usize;
            }

            i += 1;
        }

        assert!(reader.remaining_bytes().is_empty());
        out
    }

