    #[test]
    fn parses_msav_region_matrix_for_save7_through_save10() {
        for (save_version, expected_regions, expect_markers) in [
            (
                7,
                vec!["meta", "content", "map", "entities", "custom"],
                false,
            ),
            (
                8,
                vec!["meta", "content", "map", "entities", "markers", "custom"],
                true,
            ),
            (
                9,
                vec!["meta", "content", "map", "entities", "markers", "custom"],
                true,
            ),
            (
                10,
                vec!["meta", "content", "map", "entities", "markers", "custom"],
                true,
            ),
        ] {
            let save = parse_msav_save(&sample_msav_save_bytes(save_version)).unwrap();

            assert_eq!(save.envelope.save_version, save_version);
            assert_eq!(save.envelope.leading_region_length, Some(2));
            assert_eq!(save.region_names(), expected_regions);
            assert_eq!(
                save.regions
                    .iter()
                    .map(|region| region.name)
                    .collect::<Vec<_>>(),
                expected_regions
            );
            assert_eq!(save.region("markers").is_some(), expect_markers);
            assert!(save.region("custom").is_some());
            assert_eq!(save.region("meta").unwrap().chunk_bytes, vec![0xde, 0xad]);
            assert_eq!(save.region("custom").unwrap().chunk_bytes, vec![0x44, 0x55]);
            if expect_markers {
                assert_eq!(save.region("markers").unwrap().chunk_bytes, vec![0x33]);
            }
        }
    }

    #[test]
    fn parses_save6_entities_region_with_legacy_short_chunks() {
        let bytes = sample_msav_save_bytes(6);
        let save = parse_msav_save(&bytes).unwrap();

        assert_eq!(save.envelope.save_version, 6);
        assert_eq!(save.region_names(), vec!["meta", "content", "map", "entities"]);
        assert_eq!(
            save.regions
                .iter()
                .map(|region| region.name)
                .collect::<Vec<_>>(),
            vec!["meta", "content", "map", "entities"]
        );
        assert_eq!(save.region("meta").unwrap().chunk_bytes, vec![0xde, 0xad]);
        assert_eq!(
            save.region("entities").unwrap().chunk_bytes,
            sample_save_entity_region_bytes(6)
        );
        assert_eq!(save.entities.remap_count, 1);
        assert_eq!(
            save.entities.remap_entries,
            vec![SaveEntityRemapEntry {
                custom_id: 3,
                name: "mod-unit".to_string(),
            }]
        );
        let remap_surfaces = save.entities.remap_surfaces();
        assert_eq!(
            remap_surfaces,
            vec![SaveEntityRemapSurface {
                custom_id: 3,
                name: "mod-unit",
            }]
        );
        assert_eq!(save.entities.team_count, 1);
        assert_eq!(save.entities.total_plans, 1);
        let surfaces = save.region_surfaces();
        assert_eq!(surfaces.len(), save.regions.len());
        for (surface, region) in surfaces.iter().zip(&save.regions) {
            assert_eq!(surface.name, region.name);
            assert_eq!(surface.chunk_length, region.chunk_length);
            assert_eq!(surface.chunk_sha256, region.chunk_sha256.as_str());
        }
        assert_eq!(
            save.entities.team_region_bytes,
            generate_team_plan_sample_bytes()
        );
        assert_eq!(save.entities.world_entity_count, 2);

        let first = &save.entities.entity_chunks[0];
        assert_eq!(first.chunk_len, 7);
        assert_eq!(first.class_id, 3);
        assert_eq!(first.custom_name.as_deref(), Some("mod-unit"));
        assert_eq!(first.entity_id, 0x0102_0304);
        assert_eq!(first.body_bytes, vec![0xaa, 0xbb]);
        assert_eq!(first.body_len, 2);

        let second = &save.entities.entity_chunks[1];
        assert_eq!(second.class_id, 7);
        assert_eq!(second.custom_name, None);
        assert_eq!(second.entity_id, 0x1122_3344);
        assert_eq!(second.body_bytes, vec![0xcc]);

        let surfaces = save.entities.entity_chunk_surfaces();
        assert_eq!(surfaces.len(), save.entities.entity_chunks.len());
        assert_eq!(
            surfaces[0],
            SaveEntityChunkSurface {
                chunk_len: first.chunk_len,
                chunk_sha256: first.chunk_sha256.as_str(),
                class_id: first.class_id,
                custom_name: first.custom_name.as_deref(),
                entity_id: first.entity_id,
                body_len: first.body_len,
                body_sha256: first.body_sha256.as_str(),
            }
        );
        assert_eq!(
            surfaces[1],
            SaveEntityChunkSurface {
                chunk_len: second.chunk_len,
                chunk_sha256: second.chunk_sha256.as_str(),
                class_id: second.class_id,
                custom_name: second.custom_name.as_deref(),
                entity_id: second.entity_id,
                body_len: second.body_len,
                body_sha256: second.body_sha256.as_str(),
            }
        );
    }

