    fn test_building_center(
        tile_index: usize,
        x: usize,
        y: usize,
        block_id: u16,
        tail_bytes: Vec<u8>,
        parsed_tail: ParsedBuildingTail,
    ) -> BuildingCenter {
        let chunk_sha256 = sha256_hex(&tail_bytes);
        BuildingCenter {
            tile_index,
            x,
            y,
            block_id,
            chunk_len: tail_bytes.len(),
            chunk_bytes: tail_bytes.clone(),
            chunk_sha256,
            building: BuildingSnapshot {
                revision: 1,
                base_len: 0,
                base: BuildingBaseSnapshot {
                    health_bits: 1.0f32.to_bits(),
                    rotation: 0,
                    team_id: 0,
                    legacy: true,
                    save_version: None,
                    enabled: None,
                    module_bitmask: None,
                    item_module: None,
                    power_module: None,
                    liquid_module: None,
                    time_scale_bits: None,
                    time_scale_duration_bits: None,
                    last_disabler_pos: None,
                    legacy_consume_connected: None,
                    efficiency: None,
                    optional_efficiency: None,
                    visible_flags: None,
                },
                tail_len: tail_bytes.len(),
                tail_bytes: tail_bytes.clone(),
                tail_sha256: sha256_hex(&tail_bytes),
                parsed_tail,
            },
        }
    }

    fn encode_legacy_building_chunk(tail_bytes: &[u8]) -> Vec<u8> {
        let mut chunk = Vec::new();
        chunk.push(1);
        chunk.extend_from_slice(&1.0f32.to_bits().to_be_bytes());
        chunk.push(0);
        chunk.push(1);
        chunk.extend_from_slice(tail_bytes);
        chunk
    }

    fn encode_modern_power_building_chunk(links: &[i32], status_bits: u32) -> Vec<u8> {
        let mut chunk = Vec::new();
        chunk.push(2);
        chunk.extend_from_slice(&1.0f32.to_bits().to_be_bytes());
        chunk.push(0x80);
        chunk.push(1);
        chunk.push(3);
        chunk.push(1);
        chunk.push(2);
        chunk.extend_from_slice(&(links.len() as u16).to_be_bytes());
        for link in links {
            chunk.extend_from_slice(&link.to_be_bytes());
        }
        chunk.extend_from_slice(&status_bits.to_be_bytes());
        chunk.push(0x80);
        chunk.push(0x40);
        chunk
    }

    fn encode_message_tail_bytes(message: &str) -> Vec<u8> {
        let mut bytes = Vec::new();
        write_java_utf(&mut bytes, message).expect("message tail should fit java utf encoding");
        bytes
    }

    fn marker_pos_value(x: f32, y: f32) -> UbjsonValue {
        UbjsonValue::Object(vec![
            ("x".to_string(), UbjsonValue::Float32(x.to_bits())),
            ("y".to_string(), UbjsonValue::Float32(y.to_bits())),
        ])
    }

    fn marker_object(class_tag: &str, extra_fields: Vec<(String, UbjsonValue)>) -> UbjsonValue {
        let mut fields = vec![
            (
                "class".to_string(),
                UbjsonValue::String(class_tag.to_string()),
            ),
            ("pos".to_string(), marker_pos_value(16.0, 24.0)),
        ];
        fields.extend(extra_fields);
        UbjsonValue::Object(fields)
    }

