    #[test]
    fn parses_message_building_tails() {
        let message = "line 1\nline 2";
        let tail_bytes = encode_message_tail_bytes(message);

        for block_name in ["message", "reinforced-message", "world-message"] {
            let parsed = parse_building_tail(Some(block_name), 1, &tail_bytes).unwrap();
            assert_eq!(
                parsed,
                ParsedBuildingTail::Message(MessageTailSnapshot {
                    message: message.to_string(),
                })
            );
        }
    }

    #[test]
    fn parses_message_building_snapshots_from_world_chunks() {
        let message = "sector briefing";
        let tail_bytes = encode_message_tail_bytes(message);
        let chunk = encode_legacy_building_chunk(&tail_bytes);

        for block_name in ["message", "reinforced-message", "world-message"] {
            let snapshot = parse_building_snapshot(&[], Some(block_name), &chunk).unwrap();
            assert_eq!(snapshot.revision, 1);
            assert_eq!(snapshot.base.health_bits, 1.0f32.to_bits());
            assert_eq!(snapshot.base.rotation, 0);
            assert_eq!(snapshot.base.team_id, 1);
            assert_eq!(snapshot.tail_bytes, tail_bytes);
            assert_eq!(
                snapshot.parsed_tail,
                ParsedBuildingTail::Message(MessageTailSnapshot {
                    message: message.to_string(),
                })
            );
        }
    }

    #[test]
    fn parses_power_building_snapshots_from_world_chunks() {
        let chunk = encode_modern_power_building_chunk(&[3, 7], 0x0506_0708);
        let expected_power_module = BuildingPowerModuleSnapshot {
            link_count: 2,
            links: vec![3, 7],
            status_bits: 0x0506_0708,
        };

        for block_name in ["power-node", "power-node-large", "surge-tower", "beam-link"] {
            let snapshot = parse_building_snapshot(&[], Some(block_name), &chunk).unwrap();
            assert_eq!(snapshot.revision, 2);
            assert_eq!(snapshot.base.save_version, Some(3));
            assert_eq!(snapshot.base.enabled, Some(true));
            assert_eq!(snapshot.base.module_bitmask, Some(2));
            assert_eq!(
                snapshot.base.power_module,
                Some(expected_power_module.clone())
            );
            assert_eq!(snapshot.base.efficiency, Some(128));
            assert_eq!(snapshot.base.optional_efficiency, Some(64));
            assert_eq!(snapshot.tail_bytes, Vec::<u8>::new());
            assert_eq!(snapshot.parsed_tail, ParsedBuildingTail::Empty);
        }
    }

    #[test]
    fn parses_unknown_marker_model_for_unmapped_class() {
        let marker = parse_marker_model(&UbjsonValue::Object(vec![
            (
                "class".to_string(),
                UbjsonValue::String("MysteryMarker".to_string()),
            ),
            ("world".to_string(), UbjsonValue::Bool(false)),
            ("minimap".to_string(), UbjsonValue::Bool(true)),
            ("autoscale".to_string(), UbjsonValue::Bool(true)),
            (
                "drawLayer".to_string(),
                UbjsonValue::Float32(9.5f32.to_bits()),
            ),
            ("pos".to_string(), marker_pos_value(16.0, 24.0)),
        ]))
        .unwrap();

        match marker {
            MarkerModel::Unknown(unknown) => {
                assert_eq!(unknown.class_tag.as_deref(), Some("MysteryMarker"));
                assert!(!unknown.world);
                assert!(unknown.minimap);
                assert!(unknown.autoscale);
                assert_eq!(unknown.draw_layer_bits, Some(9.5f32.to_bits()));
                assert_eq!(unknown.x_bits, Some(16.0f32.to_bits()));
                assert_eq!(unknown.y_bits, Some(24.0f32.to_bits()));
            }
            _ => panic!("expected unknown marker model"),
        }
    }

