    #[test]
    fn parses_real_java_unit_payload_goldens() {
        let entries = java_unit_payload_golden_entries();

        let sample_names = entries
            .keys()
            .filter_map(|key| key.strip_prefix("unitPayload."))
            .filter_map(|key| key.strip_suffix(".classId"))
            .collect::<BTreeSet<_>>();

        assert!(sample_names.len() >= 8);
        for required in [
            "alpha",
            "mega",
            "oct",
            "quad",
            "manifold",
            "quell-missile",
            "spiroct",
            "vanquish",
        ] {
            assert!(sample_names.contains(required), "missing sample={required}");
        }

        for sample_name in sample_names {
            let class_id = u8::from_str_radix(
                entries[&format!("unitPayload.{sample_name}.classId")].as_str(),
                16,
            )
            .unwrap();
            let unit_body =
                decode_hex(entries[&format!("unitPayload.{sample_name}.bodyHex")].as_str());
            let revision = i16::from_be_bytes([unit_body[0], unit_body[1]]);
            let mut bytes = Vec::new();
            bytes.push(1);
            bytes.push(0);
            bytes.push(class_id);
            bytes.extend_from_slice(&unit_body);

            let (snapshot, consumed) = parse_payload_snapshot_bytes(&[], &bytes).unwrap();

            assert_eq!(
                snapshot,
                PayloadSnapshot::Unit(UnitPayloadSnapshot {
                    class_id,
                    revision,
                    body_len: unit_body.len(),
                    body_sha256: sha256_hex(&unit_body),
                }),
                "sample={sample_name}"
            );
            assert_eq!(
                consumed,
                1 + 1 + 1 + unit_body.len(),
                "sample={sample_name}"
            );
        }
    }

