    #[test]
    fn parses_item_bridge_and_buffered_item_bridge_tails() {
        let pack_time_item = |data: i16, item_id: i16, time_bits: u32| {
            ((time_bits as u64) << 32) | (((item_id as u16) as u64) << 16) | ((data as u16) as u64)
        };

        let item_bridge = parse_building_tail(Some("phase-conveyor"), 1, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x01020304i32.to_be_bytes());
            bytes.extend_from_slice(&0x3f400000u32.to_be_bytes());
            bytes.push(2);
            bytes.extend_from_slice(&0x11121314i32.to_be_bytes());
            bytes.extend_from_slice(&0x21222324i32.to_be_bytes());
            bytes.push(1);
            bytes
        })
        .unwrap();
        assert_eq!(
            item_bridge,
            ParsedBuildingTail::ItemBridge(ItemBridgeTailSnapshot {
                link: 0x01020304,
                warmup_bits: 0x3f400000,
                incoming: vec![0x11121314, 0x21222324],
                moved: true,
            })
        );

        let buffered = parse_building_tail(Some("bridge-conveyor"), 1, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x0a0b0c0di32.to_be_bytes());
            bytes.extend_from_slice(&0x3f800000u32.to_be_bytes());
            bytes.push(1);
            bytes.extend_from_slice(&0x10203040i32.to_be_bytes());
            bytes.push(0);
            bytes.push(5);
            bytes.push(3);
            bytes.extend_from_slice(&pack_time_item(-1, 2, 0x41200000).to_be_bytes());
            bytes.extend_from_slice(&pack_time_item(7, 3, 0x41a00000).to_be_bytes());
            bytes.extend_from_slice(&pack_time_item(9, 4, 0x42200000).to_be_bytes());
            bytes
        })
        .unwrap();
        assert_eq!(
            buffered,
            ParsedBuildingTail::BufferedItemBridge(BufferedItemBridgeTailSnapshot {
                bridge: ItemBridgeTailSnapshot {
                    link: 0x0a0b0c0d,
                    warmup_bits: 0x3f800000,
                    incoming: vec![0x10203040],
                    moved: false,
                },
                buffer: ItemBufferTailSnapshot {
                    index: 5,
                    capacity: 3,
                    normalized_index: 2,
                    entries: vec![
                        TimeItemSnapshot {
                            raw: pack_time_item(-1, 2, 0x41200000),
                            data: -1,
                            item_id: 2,
                            time_bits: 0x41200000,
                        },
                        TimeItemSnapshot {
                            raw: pack_time_item(7, 3, 0x41a00000),
                            data: 7,
                            item_id: 3,
                            time_bits: 0x41a00000,
                        },
                        TimeItemSnapshot {
                            raw: pack_time_item(9, 4, 0x42200000),
                            data: 9,
                            item_id: 4,
                            time_bits: 0x42200000,
                        },
                    ],
                },
            })
        );

        let liquid_bridge = parse_building_tail(Some("phase-conduit"), 1, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x31323334i32.to_be_bytes());
            bytes.extend_from_slice(&0x3f000000u32.to_be_bytes());
            bytes.push(1);
            bytes.extend_from_slice(&0x41424344i32.to_be_bytes());
            bytes.push(0);
            bytes
        })
        .unwrap();
        assert_eq!(
            liquid_bridge,
            ParsedBuildingTail::ItemBridge(ItemBridgeTailSnapshot {
                link: 0x31323334,
                warmup_bits: 0x3f000000,
                incoming: vec![0x41424344],
                moved: false,
            })
        );
    }

