    #[test]
    fn parses_turret_family_tails() {
        let wave = parse_building_tail(Some("wave"), 1, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x3f800000u32.to_be_bytes());
            bytes.extend_from_slice(&0x41200000u32.to_be_bytes());
            bytes
        })
        .unwrap();
        assert_eq!(
            wave,
            ParsedBuildingTail::Turret(TurretTailSnapshot {
                reload_counter_bits: 0x3f800000,
                rotation_bits: 0x41200000,
            })
        );

        let segment =
            parse_building_tail(Some("segment"), 0, &0x41700000u32.to_be_bytes()).unwrap();
        assert_eq!(
            segment,
            ParsedBuildingTail::OneF32(OneF32TailSnapshot { bits: 0x41700000 })
        );

        let parallax =
            parse_building_tail(Some("parallax"), 0, &0x41a00000u32.to_be_bytes()).unwrap();
        assert_eq!(
            parallax,
            ParsedBuildingTail::OneF32(OneF32TailSnapshot { bits: 0x41a00000 })
        );

        let duo = parse_building_tail(Some("duo"), 2, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x3e800000u32.to_be_bytes());
            bytes.extend_from_slice(&0x42700000u32.to_be_bytes());
            bytes.push(2);
            bytes.extend_from_slice(&0x0012u16.to_be_bytes());
            bytes.extend_from_slice(&3i16.to_be_bytes());
            bytes.extend_from_slice(&0x0034u16.to_be_bytes());
            bytes.extend_from_slice(&9i16.to_be_bytes());
            bytes
        })
        .unwrap();
        assert_eq!(
            duo,
            ParsedBuildingTail::ItemTurret(ItemTurretTailSnapshot {
                turret: TurretTailSnapshot {
                    reload_counter_bits: 0x3e800000,
                    rotation_bits: 0x42700000,
                },
                ammo_count: 2,
                ammo: vec![
                    ItemTurretAmmoEntrySnapshot {
                        item_id: 0x0012,
                        amount: 3,
                    },
                    ItemTurretAmmoEntrySnapshot {
                        item_id: 0x0034,
                        amount: 9,
                    },
                ],
            })
        );

        let scorch = parse_building_tail(Some("scorch"), 1, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x3f000000u32.to_be_bytes());
            bytes.extend_from_slice(&0x41f00000u32.to_be_bytes());
            bytes.push(1);
            bytes.push(7);
            bytes.extend_from_slice(&5i16.to_be_bytes());
            bytes
        })
        .unwrap();
        assert_eq!(
            scorch,
            ParsedBuildingTail::ItemTurret(ItemTurretTailSnapshot {
                turret: TurretTailSnapshot {
                    reload_counter_bits: 0x3f000000,
                    rotation_bits: 0x41f00000,
                },
                ammo_count: 1,
                ammo: vec![ItemTurretAmmoEntrySnapshot {
                    item_id: 7,
                    amount: 5,
                }],
            })
        );

        let lustre = parse_building_tail(Some("lustre"), 3, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0x3f400000u32.to_be_bytes());
            bytes.extend_from_slice(&0x43070000u32.to_be_bytes());
            bytes.extend_from_slice(&0x41a80000u32.to_be_bytes());
            bytes
        })
        .unwrap();
        assert_eq!(
            lustre,
            ParsedBuildingTail::ContinuousTurret(ContinuousTurretTailSnapshot {
                turret: TurretTailSnapshot {
                    reload_counter_bits: 0x3f400000,
                    rotation_bits: 0x43070000,
                },
                last_length_bits: 0x41a80000,
            })
        );
    }

    #[test]
    fn parses_build_turret_tail_with_plan_queue() {
        let config_bytes = {
            let mut bytes = Vec::new();
            bytes.push(7);
            bytes.extend_from_slice(&3i32.to_be_bytes());
            bytes.extend_from_slice(&4i32.to_be_bytes());
            bytes
        };
        let build_turret = parse_building_tail(Some("build-tower"), 0, &{
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&90.0f32.to_bits().to_be_bytes());
            bytes.extend_from_slice(&(2i16).to_be_bytes());
            bytes.push(0);
            bytes.extend_from_slice(&pack_packed_point2(1, 2).to_be_bytes());
            bytes.extend_from_slice(&0x0101u16.to_be_bytes());
            bytes.push(1);
            bytes.push(1);
            bytes.extend_from_slice(&config_bytes);
            bytes.push(1);
            bytes.extend_from_slice(&pack_packed_point2(5, 6).to_be_bytes());
            bytes
        })
        .unwrap();
        assert_eq!(
            build_turret,
            ParsedBuildingTail::BuildTurret(BuildTurretTailSnapshot {
                rotation_bits: 90.0f32.to_bits(),
                plans_present: true,
                plan_count: 2,
                plans: vec![
                    BuildTurretPlanSnapshot {
                        breaking: false,
                        packed_position: pack_packed_point2(1, 2),
                        x: 1,
                        y: 2,
                        block_id: Some(0x0101),
                        rotation: Some(1),
                        has_config: true,
                        config_kind: "Point2".to_string(),
                        config_value: "00000003:00000004".to_string(),
                        config_sha256: sha256_hex(&config_bytes),
                        config_bytes,
                    },
                    BuildTurretPlanSnapshot {
                        breaking: true,
                        packed_position: pack_packed_point2(5, 6),
                        x: 5,
                        y: 6,
                        block_id: None,
                        rotation: None,
                        has_config: false,
                        config_kind: "none".to_string(),
                        config_value: "none".to_string(),
                        config_sha256: "none".to_string(),
                        config_bytes: Vec::new(),
                    },
                ],
            })
        );
    }

