    #[test]
    fn world_graph_exposes_unified_queries() {
        let hex = include_str!("../../../tests/src/test/resources/world-stream.hex")
            .replace(char::is_whitespace, "");
        let compressed = (0..hex.len())
            .step_by(2)
            .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap())
            .collect::<Vec<_>>();
        let bundle = parse_world_bundle(&compressed).unwrap();
        let graph = bundle.graph();

        assert_eq!(graph.width(), 8);
        assert_eq!(graph.height(), 8);
        assert_eq!(graph.tile(4, 4).unwrap().tile_index, 36);
        assert!(graph.building_center_at(4, 4).is_some());
        assert!(!graph.markers_are_empty());
        assert_eq!(graph.markers().count(), 2);
        assert_eq!(graph.marker(11).unwrap().marker.tile_coords(), Some((4, 4)));
        assert_eq!(
            graph.marker_region(),
            generate_marker_sample_bytes().as_slice()
        );
        assert_eq!(graph.custom_chunks().count(), 1);
        assert_eq!(graph.static_fog_chunk().unwrap().width, 8);
        assert_eq!(graph.fog_revealed(1, 4, 4), Some(true));
        assert_eq!(graph.fog_revealed(5, 4, 4), Some(false));
        assert!(graph.team_plan_group(1).is_some());
        assert_eq!(graph.all_team_plans().count(), 1);
        assert_eq!(graph.team_plans_at(1, 2).len(), 1);
        assert_eq!(graph.markers_at_tile(1, 2).len(), 1);
    }

