    #[test]
    fn world_bundle_builds_enter_init_envelope() {
        let bundle = sample_world_bundle();
        let envelope = bundle.enter_init_envelope("fr").unwrap();
        let checklist = envelope.checklist();
        let plan = envelope.plan();
        let gate = envelope.ready_gate();
        let loading = envelope.loading_state();

        assert_eq!(envelope.locale(), "fr");
        assert!(envelope.context().rules.is_object());
        assert_eq!(
            envelope.context().tags.get("name").map(String::as_str),
            Some("Golden Deterministic")
        );
        assert_eq!(
            envelope.bootstrap().display_title.as_deref(),
            Some("Golden Deterministic")
        );
        assert_eq!(envelope.transport().tail_length, 0x00d7);
        assert_eq!(envelope.content().first_item_name, Some("copper"));
        assert_eq!(envelope.player().player_team_id, 1);
        assert_eq!(envelope.world().map_width, 8);
        assert_eq!(envelope.overlay().team_count, 1);
        assert!(checklist.has_transport);
        assert!(checklist.has_content);
        assert!(checklist.has_player);
        assert!(checklist.has_world);
        assert!(checklist.has_overlay);
        assert!(checklist.is_complete());
        assert!(envelope.missing_sections().is_empty());
        assert_eq!(plan.locale, "fr");
        assert_eq!(plan.display_title.as_deref(), Some("Golden Deterministic"));
        assert_eq!(
            plan.display_title_source,
            WorldEnterDisplayTitleSource::TagName
        );
        assert_eq!(plan.fog_enabled, Some(true));
        assert!(plan.can_enter_world());
        assert_eq!(
            gate.display_title_source,
            WorldEnterDisplayTitleSource::TagName
        );
        assert!(gate.blocking_reasons.is_empty());
        assert!(gate.can_enter_world);
        assert_eq!(loading.status, WorldEnterLoadingStatus::Ready);
        assert!(loading.blocking_tags.is_empty());
        assert!(envelope.is_ready());
    }

    #[test]
    fn world_bundle_builds_enter_init_state() {
        let bundle = sample_world_bundle();
        let state = bundle.enter_init_state("fr").unwrap();
        let plan = state.plan();
        let gate = state.ready_gate();
        let loading = state.loading_state();

        assert_eq!(state.locale, "fr");
        assert!(state.context.rules.is_object());
        assert_eq!(
            state.context.tags.get("name").map(String::as_str),
            Some("Golden Deterministic")
        );
        assert_eq!(state.context.map_locales.get("fr"), None);
        assert!(state.context.content_patches.is_empty());
        assert_eq!(state.transport.tail_length, 0x00d7);
        assert_eq!(state.content.first_block_name.as_deref(), Some("air"));
        assert_eq!(state.player.player_team_id, 1);
        assert_eq!(state.world.map_width, 8);
        assert_eq!(state.overlay.team_ids, vec![1]);
        assert!(state.checklist.is_complete());
        assert!(state.missing_sections.is_empty());
        assert_eq!(plan.locale, "fr");
        assert_eq!(plan.display_title.as_deref(), Some("Golden Deterministic"));
        assert_eq!(
            plan.display_title_source,
            WorldEnterDisplayTitleSource::TagName
        );
        assert_eq!(plan.fog_enabled, Some(true));
        assert!(plan.can_enter_world());
        assert_eq!(
            gate.display_title_source,
            WorldEnterDisplayTitleSource::TagName
        );
        assert!(gate.blocking_reasons.is_empty());
        assert_eq!(gate.blocking_reason_tags(), Vec::<&'static str>::new());
        assert!(!gate.is_blocked());
        assert_eq!(loading.status, WorldEnterLoadingStatus::Ready);
        assert!(loading.blocking_tags.is_empty());
        assert!(state.is_complete());
        assert!(state.is_ready());
    }

