    #[test]
    fn parses_non_zero_team_plan_group_with_point2_config() {
        let bytes = generate_team_plan_sample_bytes();

        let mut reader = Reader::new(&bytes);
        let parsed = parse_team_plan_groups(&mut reader).unwrap();
        assert_eq!(parsed.team_count, 1);
        assert_eq!(parsed.total_plans, 1);
        assert_eq!(parsed.team_ids, vec![1]);
        assert_eq!(parsed.team_plan_counts, vec![1]);
        assert_eq!(parsed.team_region_bytes, bytes[4..].to_vec());

        let group = &parsed.team_plan_groups[0];
        assert_eq!(group.team_id, 1);
        assert_eq!(group.plan_count, 1);
        assert_eq!(group.plans.len(), 1);
        let plan = &group.plans[0];
        assert_eq!(plan.x, 1);
        assert_eq!(plan.y, 2);
        assert_eq!(plan.rotation, 1);
        assert_eq!(plan.block_id, 0x0101);
        assert_eq!(plan.config, TypeIoValue::Point2 { x: 3, y: 4 });
        assert_eq!(plan.config_bytes, vec![7, 0, 0, 0, 3, 0, 0, 0, 4]);
        assert!(reader.remaining_bytes().is_empty());
    }

    #[test]
    fn formats_team_plan_goldens_for_non_zero_sample() {
        let bytes = generate_team_plan_sample_bytes();
        let summary = parse_team_plan_goldens(&bytes).unwrap();
        let text = format_team_plan_goldens(&summary);
        assert!(text.contains("teamBlocks.teamCount=00000001"));
        assert!(text.contains("teamBlocks.totalPlans=00000001"));
        assert!(text.contains("teamPlans.count=00000001"));
        assert!(text.contains("teamPlans.configKinds=Point2"));
    }

