    #[test]
    fn rejects_excessive_team_plan_group_counts() {
        let bytes = u32::MAX.to_be_bytes().to_vec();
        let mut reader = Reader::new(&bytes);
        let error = parse_team_plan_groups(&mut reader).err().unwrap();
        assert!(error.contains("too many teams"));

        let mut bytes = Vec::new();
        bytes.extend_from_slice(&1u32.to_be_bytes());
        bytes.extend_from_slice(&1u32.to_be_bytes());
        bytes.extend_from_slice(&u32::MAX.to_be_bytes());
        let mut reader = Reader::new(&bytes);
        let error = parse_team_plan_groups(&mut reader).err().unwrap();
        assert!(error.contains("too many plans"));
    }

    #[test]
    fn parses_static_fog_sample_and_exposes_queries() {
        let bytes = generate_static_fog_sample_bytes();
        let chunk = parse_static_fog_chunk(&bytes).unwrap();

        assert_eq!(chunk.used_teams, 2);
        assert_eq!(chunk.width, 4);
        assert_eq!(chunk.height, 3);
        assert_eq!(chunk.team(1).unwrap().discovered_count(), 5);
        assert_eq!(chunk.team(5).unwrap().discovered_count(), 5);
        assert_eq!(
            chunk.team(1).unwrap().discovered_indices(),
            vec![0, 1, 4, 5, 10]
        );
        assert_eq!(
            chunk.team(5).unwrap().discovered_indices(),
            vec![3, 7, 8, 9, 11]
        );
        assert_eq!(chunk.is_discovered(1, 0, 0), Some(true));
        assert_eq!(chunk.is_discovered(1, 3, 0), Some(false));
        assert_eq!(chunk.is_discovered(5, 3, 0), Some(true));
        assert_eq!(chunk.is_discovered(5, 0, 0), Some(false));
        assert_eq!(chunk.is_discovered(1, 4, 0), None);
    }

    #[test]
    fn parses_small_save_map_region() {
        let mut bytes = Vec::new();
        bytes.extend_from_slice(&1u16.to_be_bytes());
        bytes.extend_from_slice(&1u16.to_be_bytes());
        bytes.extend_from_slice(&0x0011u16.to_be_bytes());
        bytes.extend_from_slice(&0x0022u16.to_be_bytes());
        bytes.push(0);
        bytes.extend_from_slice(&0x0033u16.to_be_bytes());
        bytes.push(0);
        bytes.push(0);

        let parsed = parse_save_map_region(11, &[], &bytes).unwrap();
        assert_eq!(parsed.world.width, 1);
        assert_eq!(parsed.world.height, 1);
        assert_eq!(parsed.world.floors, vec![0x0011]);
        assert_eq!(parsed.world.overlays, vec![0x0022]);
        assert_eq!(parsed.world.blocks, vec![0x0033]);
        assert!(parsed.world.building_centers.is_empty());
    }

