    #[test]
    fn parses_legacy_memory_family_building_snapshots_when_block_name_is_known() {
        let expected_bits = vec![1.5f64.to_bits(), f64::NAN.to_bits()];
        let legacy_tail = {
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&(expected_bits.len() as i32).to_be_bytes());
            for bits in &expected_bits {
                bytes.extend_from_slice(&bits.to_be_bytes());
            }
            bytes
        };

        for block_name in ["memory-cell", "memory-bank", "world-cell"] {
            let expected = parse_building_tail(Some(block_name), 1, &legacy_tail).unwrap();
            let snapshot = parse_legacy_save_building_snapshot(Some(block_name), &{
                let mut bytes = vec![1, 0, 10, 0x12, 1];
                bytes.extend_from_slice(&legacy_tail);
                bytes
            })
            .unwrap();

            assert_eq!(snapshot.parsed_tail, expected);
        }
    }

    #[test]
    fn parses_legacy_junction_building_snapshot_when_block_name_is_known() {
        let pack_directional_legacy =
            |item_id: u8, time_bits: u32| ((time_bits as u64) << 8) | (item_id as u64);
        let legacy_tail = {
            let mut bytes = Vec::new();
            bytes.push(0);
            bytes.push(1);
            bytes.extend_from_slice(&pack_directional_legacy(9, 0x40a00000).to_be_bytes());
            bytes.push(0);
            bytes.push(0);
            bytes.push(0);
            bytes.push(0);
            bytes.push(0);
            bytes.push(0);
            bytes
        };
        let expected = parse_building_tail(Some("junction"), 0, &legacy_tail).unwrap();
        let snapshot = parse_legacy_save_building_snapshot(Some("junction"), &{
            let mut bytes = vec![0, 0, 10, 0x12, 1];
            bytes.extend_from_slice(&legacy_tail);
            bytes
        })
        .unwrap();

        assert_eq!(snapshot.parsed_tail, expected);
    }

