    #[test]
    fn formats_payload_campaign_compound_goldens_for_constructor_and_landing_pad() {
        let constructor_tail_bytes = {
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&0u32.to_be_bytes());
            bytes.extend_from_slice(&0u32.to_be_bytes());
            bytes.extend_from_slice(&0u32.to_be_bytes());
            bytes.push(0);
            bytes.extend_from_slice(&0u32.to_be_bytes());
            bytes.extend_from_slice(&(-1i16).to_be_bytes());
            bytes
        };
        let constructor_tail = ParsedBuildingTail::Constructor(ConstructorTailSnapshot {
            payload_block: PayloadBlockTailSnapshot {
                pay_vector_x_bits: 0,
                pay_vector_y_bits: 0,
                pay_rotation_bits: 0,
                payload_present: false,
                payload_type: None,
                build_block_id: None,
                build_revision: None,
                build_payload: None,
                unit_class_id: None,
                unit_payload_len: None,
                unit_payload_sha256: None,
            },
            progress_bits: 0,
            recipe_block_id: None,
        });

        let landing_pad_tail_bytes = {
            let mut bytes = Vec::new();
            bytes.extend_from_slice(&(-1i16).to_be_bytes());
            bytes.extend_from_slice(&10i32.to_be_bytes());
            bytes.extend_from_slice(&0x3f000000u32.to_be_bytes());
            bytes.extend_from_slice(&(-1i16).to_be_bytes());
            bytes.extend_from_slice(&0x3e800000u32.to_be_bytes());
            bytes.extend_from_slice(&0x41480000u32.to_be_bytes());
            bytes
        };
        let landing_pad_tail = ParsedBuildingTail::LandingPad(LandingPadTailSnapshot {
            config_item_id: None,
            priority: 10,
            cooldown_bits: 0x3f000000,
            arriving_item_id: None,
            arriving_timer_bits: 0x3e800000,
            liquid_removed_bits: 0x41480000,
        });

        let constructor_center =
            test_building_center(0, 0, 0, 0x0101, constructor_tail_bytes, constructor_tail);
        let landing_center =
            test_building_center(1, 1, 0, 0x0111, landing_pad_tail_bytes, landing_pad_tail);

        let model = WorldModel {
            width: 2,
            height: 1,
            floors: vec![0, 0],
            overlays: vec![0, 0],
            blocks: vec![0x0101, 0x0111],
            tiles: vec![
                TileModel {
                    tile_index: 0,
                    x: 0,
                    y: 0,
                    floor_id: 0,
                    overlay_id: 0,
                    block_id: 0x0101,
                    building_center_index: Some(0),
                },
                TileModel {
                    tile_index: 1,
                    x: 1,
                    y: 0,
                    floor_id: 0,
                    overlay_id: 0,
                    block_id: 0x0111,
                    building_center_index: Some(1),
                },
            ],
            building_centers: vec![constructor_center, landing_center],
            data_tiles: 0,
            team_count: 0,
            total_plans: 0,
            team_ids: Vec::new(),
            team_plan_counts: Vec::new(),
        };

        let summary = summarize_payload_campaign_compound_model(&model);
        let text = format_payload_campaign_compound_goldens(&summary);

        assert!(text.contains("payloadCampaignCompound.constructors.0.payload.present=0"));
        assert!(text.contains(
            "payloadCampaignCompound.constructors.0.tail.constructor.progressBits=00000000"
        ));
        assert!(text.contains(
            "payloadCampaignCompound.constructors.0.tail.constructor.recipeBlockId=none"
        ));
        assert!(text
            .contains("payloadCampaignCompound.landingPads.0.tail.landingPad.configItemId=none"));
        assert!(text
            .contains("payloadCampaignCompound.landingPads.0.tail.landingPad.priority=0000000a"));
        assert!(text.contains(
            "payloadCampaignCompound.landingPads.0.tail.landingPad.cooldownBits=3f000000"
        ));
        assert!(text
            .contains("payloadCampaignCompound.landingPads.0.tail.landingPad.arrivingItemId=none"));
        assert!(text.contains(
            "payloadCampaignCompound.landingPads.0.tail.landingPad.liquidRemovedBits=41480000"
        ));
    }

