    #[test]
    fn world_graph_nodes_merge_tile_plan_and_fog_queries() {
        let hex = include_str!("../../../tests/src/test/resources/world-stream.hex")
            .replace(char::is_whitespace, "");
        let compressed = (0..hex.len())
            .step_by(2)
            .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap())
            .collect::<Vec<_>>();
        let bundle = parse_world_bundle(&compressed).unwrap();
        let graph = bundle.graph();

        let plan = graph.node(1, 2).unwrap();
        assert_eq!(plan.tile().tile_index, 17);
        assert_eq!(plan.building_center().unwrap().block_id, 0x0101);
        assert_eq!(plan.team_plans().len(), 1);
        assert_eq!(plan.team_plans()[0].team_id, 1);
        assert_eq!(plan.markers().len(), 1);
        assert_eq!(plan.markers()[0].id, 24);
        assert_eq!(plan.fog_revealed(1), Some(true));
        assert_eq!(plan.fog_revealed(5), Some(false));

        let core = graph.node(4, 4).unwrap();
        assert_eq!(core.tile().block_id, 0x0153);
        assert_eq!(core.building_center().unwrap().block_id, 0x0153);
        assert!(core.team_plans().is_empty());
        assert_eq!(core.markers().len(), 1);
        assert_eq!(core.markers()[0].id, 11);
        assert_eq!(core.fog_revealed(1), Some(true));
        assert_eq!(core.fog_revealed(5), Some(false));

        let wall = graph.node(0, 7).unwrap();
        assert_eq!(wall.tile().block_id, 0x00e6);
        assert_eq!(wall.building_center().unwrap().block_id, 0x00e6);
        assert!(wall.markers().is_empty());
        assert_eq!(wall.fog_revealed(1), Some(false));
        assert_eq!(wall.fog_revealed(5), Some(true));

        let wall_edge = graph.node(7, 7).unwrap();
        assert_eq!(wall_edge.tile().block_id, 0x00e7);
        assert!(wall_edge.building_center().is_none());
        assert!(wall_edge.team_plans().is_empty());
        assert!(wall_edge.markers().is_empty());
        assert_eq!(wall_edge.fog_revealed(1), Some(false));
        assert_eq!(wall_edge.fog_revealed(5), Some(true));
    }

    #[test]
    fn formats_world_graph_goldens_for_overlay_queries() {
        let hex = include_str!("../../../tests/src/test/resources/world-stream.hex")
            .replace(char::is_whitespace, "");
        let compressed = (0..hex.len())
            .step_by(2)
            .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap())
            .collect::<Vec<_>>();
        let summary = parse_world_graph_goldens(&compressed).unwrap();
        let text = format_world_graph_goldens(&summary);

        assert!(text.contains("graph.width=0008"));
        assert!(text.contains("graph.staticFog.width=0008"));
        assert!(text.contains("graph.markerSample.count=00000002"));
        assert!(text.contains("node.plan.planCount=00000001"));
        assert!(text.contains("node.plan.markerIds=00000018"));
        assert!(text.contains("node.core.markerIds=0000000b"));
        assert!(text.contains("node.plan.fog.01=1"));
        assert!(text.contains("node.wall.fog.05=1"));
        assert!(text.contains("node.wallEdge.centerBlock=none"));
    }

